WITH payload AS (
  SELECT $RISQQ31${"questions":[{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.8","internal_question_no":"04A.008","question_sort_key":4100800.05,"question_text":"Has a specific permit to work, Lock-Out/Tag-Out (LOTO) system, and Stop Work Authority policy and procedure been introduced and are they being used effectively?","guide_to_inspection":"The vessel’s manager should identify the High-risk tasks on board and create a specific permit and risk assessment system for\nthe ship .\nThe safety management system for individual ships will determine when permit to work systems should be used, and the form\nof the permit to work. (Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nWherever there is a high-risk job taking place, a written permit to work procedure should always be used. Jobs considered to be\nhigh risk should include:\n> Entry into enclosed or confined spaces.\n> Working on machinery or equipment which can start automatically or requires isolation.\n> Hot work including welding.\n> Working aloft or overside.\n> General electrical work (Under 1000 Volts).\n> Electrical high voltage work (Over 1000 Volts).\n> Working on elevator, and\n> Underwater Operation.\nAdditional Permits to Work may be required depending on the trade of the ship and the work carried out. Permits can be\nindividual or cover a number of work types.\nWorking aloft or overside:\n> The ship’s manager shall specify a height above a deck or tank top that is considered to be “working aloft or from height,\n> Define the meaning of working over or near the side.\n> Identify shipboard tasks that may require a seafarer to work from height or over the side and the need for the risk\nassessments for those tasks to identify and address the associated hazards.\n> Identify practical alternatives for completing routine-routine tasks without a seafarer needing to work from height or over\nthe side;\n> Articulate the need for all seafarers to remain vigilant-vigilant and exercise care whenever they move about the ship.\nPlant is a general name for equipment, machinery, appliances, tools and implements. Every year, seafarers at work\nare injured, sometimes fatally, when plant inadvertently activates or stored energy including electricity, heat, steam,\ncoiled,tension,compression,pressure and fluids released during inspection, repair, maintenance, or cleaning. The vessel’s\nmanager shall implement an effective isolation procedure into the ship’s SMS.\nA procedure for working over the side to rig and recover accommodation ladders and combination pilot ladders should be\nincorporated into the company’s SMS. The work permit and risk assessment forms should specially identify this task taking\naccount of vessel’s movement and weather conditions.\nLock Out/Tag Out system are used to prevent contact with a hazard while performing tasks that require the removal, by-passing,\nor deactivation of safeguarding devices, and the unintended release of hazardous energy (stored energy), or the unintended\nstart-up or motion of machinery, equipment, or processes. Lock-Out/Tag-Out is a decommissioning/recommissioning work\nsystem. Decommission to make the work environment safe, and recommission to restore operational readiness.\nLock Out is the control of hazardous energy by the placement of a lock and tag on an energy-isolating device, indicating that the\nenergy-isolating device is not to be operated until removal of the lock or tag. In practice, lockout is the isolation of energy from\nthe system (a machine, equipment, or process) which physically locks the system in a safe mode. The energy-isolating device\nmay be a manually operated disconnect switch, a circuit breaker, a line valve, or a block. Push buttons, selection switches and\nother circuit control switches are not considered energy-isolating devices.\nTag Out is a labelling process that is always used when lockout is required. The process of tagging out a system involves\nattaching or using a standardised label that includes the following information:\n> Why the lockout or tag out is required (repair, maintenance, etc.).\n> Time of Application of the lock or tag; and\n> The name of the authorised person who attached the tag and lock to the system\nOnly the authorised individual who placed the lock and tag onto the system is the one who is permitted to remove them. This\nprocedure helps make sure the system cannot be started up without the authorised individual’s knowledge. The following\nstandards can be referred to for safe guidelines: AS/NZS 4836:2011, AS 4024.1603-2006.\nUnless specifically addressed by ship-specific “Gantry Crane Isolation” procedures, the crane shall be subject to the company’s\ngeneral lockout/tagout procedures under the following circumstances:\n> When not in use, to prevent unauthorized use.\n> When being worked on, to ensure the safety of maintenance staff or operators.\n> When deemed unfit for use, either following an incident, inspection, or prior to commissioning.\n> When people are working near potential power sources, such as bus bars and electrical tracks.\nStop Work Authority (SWA) Policy:\nThe company should establish a Stop Work Authority (SWA) policy that empowers all personnel, regardless of role or rank, to\nhalt any work activity that poses a risk to health, safety, the environment, or equipment.\nThis policy should clearly outline the following key requirements for implementation across all operations:\n1. Universal Authority: Every individual has the right and responsibility to stop work when unsafe conditions or behaviours are\nobserved.\n2. No Retaliation: Personnel who exercise SWA in good faith should be protected from any form of disciplinary action or retaliation.\n3. Immediate Response: Work should be stopped immediately upon identification of a hazard, and the issue should be reported\nwithout delay.\n4. Assessment & Resolution: The hazard should be assessed, corrective actions taken, and the situation resolved before work\nresumes.\n5. Training: All personnel should receive training on the SWA policy during induction and through ongoing safety briefings.\n6. Leadership Support: Managers should actively support and promote the SWA policy to foster a strong and proactive safety culture.\nStop Work Authority (SWA)\nThe SMS should include a Stop Work Authority (SWA) policy and procedure. SWA recognizes the importance of encouraging any\nemployee on board a vessel to express concern if they believe that an operation is being incorrectly undertaken or unsafe. SWA\ngives crewmembers the responsibility and obligation to intervene and stop work if they see something unsafe that may cause\nan accident.\nA typical SWA is comprised of six steps:\nStop – When you or a colleague perceive condition(s) or behaviour(s) that pose imminent danger to person(s), equipment, or the\nenvironment, they must immediately initiate a stop work intervention with the person(s) potentially at risk.\nNotify – Notify affected personnel and supervision of the stop work action.\nInvestigate – Affected personnel will discuss the situation and come to an agreement on the stop work action.\nCorrect – The affected area(s) will then be inspected by qualified experts to verify completeness of the modifications and ensure\nall safety issues have been properly resolved.\nResume – All affected personnel will be notified of what corrective actions were implemented, and the affected area(s) will be\nreopened for work by personnel with restart authority.\nFollow-up – The Safety Manager will publish the incident details regarding the stop work action to all Operations Managers and\nemployees, outlining the issue, corrective action, and lessons learned.\nToolbox talk\nA toolbox talk before the work begins is key in ensuring that all workers involved in the work understand and are aware of any\nhazards and their associated risks.\nA toolbox talk is another form of risk assessment carried out in support of a Task -Based-Risk assessment (TBRA). Its prime\npurpose is to talk through the procedures of the job in hand and the findings of the TBRA with the seafarers involved.\nA task-based risk assessment (TBRA) is a systematic approach to identify, evaluate, and control hazards associated with\nspecific tasks or activities in the workplace. It focuses on the individual steps or stages of a task to pinpoint potential hazards\nand implement targeted safety measures.\nWhen carrying out a toolbox talk, it is important to actively involve workers doing the work and others who may be at risk; in\nother words, seafarers, sub-contractors and others on board ship who may be affected. Encourage full and active participation\nand discuss any questions or concerns. Once finished, confirm that everyone fully understands their role in the task and\nthe precautions in place (this is known as ‘closed-loop communication’). Record this along with details of any relevant risk\nassessment to which you have referred.\nGive a toolbox talk before any work is carried out that involves more than one person and where there is significant risk to\npersons or assets.\n(CPSWP 2025)\nIntegrating LOTO with the Permit to Work (PTW) System\nTo ensure the highest level of safety when working with hazardous energy sources, or within spaces containing such sources,\nit is essential to integrate Lockout/Tagout (LOTO) with the Permit to Work (PTW) system. When these systems operate\nindependently, critical safety gaps can arise, such as work commencing before energy sources are fully isolated.\nKey Benefits of Integration:\n1. Ensures all hazardous energy sources are locked out before work begins.\n2. Provides a single, unified workflow for managing high-risk tasks.\n3. Enhances accountability, traceability, and regulatory compliance.\n4. Reduces the risk of human error and miscommunication.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":47,"source_page_end":48,"raw_source_text":"Has a specific permit to work, Lock-Out/Tag-Out (LOTO) system, and Stop Work Authority policy and\nprocedure been introduced and are they being used effectively? (V)\nGuide to Inspection\nThe vessel’s manager should identify the High-risk tasks on board and create a specific permit and risk assessment system for\nthe ship .\nThe safety management system for individual ships will determine when permit to work systems should be used, and the form\nof the permit to work. (Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nWherever there is a high-risk job taking place, a written permit to work procedure should always be used. Jobs considered to be\nhigh risk should include:\n> Entry into enclosed or confined spaces.\n> Working on machinery or equipment which can start automatically or requires isolation.\n> Hot work including welding.\n> Working aloft or overside.\n> General electrical work (Under 1000 Volts).\n> Electrical high voltage work (Over 1000 Volts).\n> Working on elevator, and\n> Underwater Operation.\nAdditional Permits to Work may be required depending on the trade of the ship and the work carried out. Permits can be\nindividual or cover a number of work types.\nWorking aloft or overside:\n> The ship’s manager shall specify a height above a deck or tank top that is considered to be “working aloft or from height,\n> Define the meaning of working over or near the side.\n> Identify shipboard tasks that may require a seafarer to work from height or over the side and the need for the risk\nassessments for those tasks to identify and address the associated hazards.\n> Identify practical alternatives for completing routine-routine tasks without a seafarer needing to work from height or over\nthe side;\n> Articulate the need for all seafarers to remain vigilant-vigilant and exercise care whenever they move about the ship.\nPlant is a general name for equipment, machinery, appliances, tools and implements. Every year, seafarers at work\nare injured, sometimes fatally, when plant inadvertently activates or stored energy including electricity, heat, steam,\ncoiled,tension,compression,pressure and fluids released during inspection, repair, maintenance, or cleaning. The vessel’s\nmanager shall implement an effective isolation procedure into the ship’s SMS.\nA procedure for working over the side to rig and recover accommodation ladders and combination pilot ladders should be\nincorporated into the company’s SMS. The work permit and risk assessment forms should specially identify this task taking\naccount of vessel’s movement and weather conditions.\nLock Out/Tag Out system are used to prevent contact with a hazard while performing tasks that require the removal, by-passing,\nor deactivation of safeguarding devices, and the unintended release of hazardous energy (stored energy), or the unintended\nstart-up or motion of machinery, equipment, or processes. Lock-Out/Tag-Out is a decommissioning/recommissioning work\nsystem. Decommission to make the work environment safe, and recommission to restore operational readiness.\nLock Out is the control of hazardous energy by the placement of a lock and tag on an energy-isolating device, indicating that the\nenergy-isolating device is not to be operated until removal of the lock or tag. In practice, lockout is the isolation of energy from\nthe system (a machine, equipment, or process) which physically locks the system in a safe mode. The energy-isolating device\nmay be a manually operated disconnect switch, a circuit breaker, a line valve, or a block. Push buttons, selection switches and\nother circuit control switches are not considered energy-isolating devices.\nTag Out is a labelling process that is always used when lockout is required. The process of tagging out a system involves\nattaching or using a standardised label that includes the following information:\n> Why the lockout or tag out is required (repair, maintenance, etc.).\n> Time of Application of the lock or tag; and\n> The name of the authorised person who attached the tag and lock to the system\nOnly the authorised individual who placed the lock and tag onto the system is the one who is permitted to remove them. This\nprocedure helps make sure the system cannot be started up without the authorised individual’s knowledge. The following\nstandards can be referred to for safe guidelines: AS/NZS 4836:2011, AS 4024.1603-2006.\nUnless specifically addressed by ship-specific “Gantry Crane Isolation” procedures, the crane shall be subject to the company’s\ngeneral lockout/tagout procedures under the following circumstances:\n> When not in use, to prevent unauthorized use.\n> When being worked on, to ensure the safety of maintenance staff or operators.\n> When deemed unfit for use, either following an incident, inspection, or prior to commissioning.\n> When people are working near potential power sources, such as bus bars and electrical tracks.\nStop Work Authority (SWA) Policy:\nThe company should establish a Stop Work Authority (SWA) policy that empowers all personnel, regardless of role or rank, to\nhalt any work activity that poses a risk to health, safety, the environment, or equipment.\nThis policy should clearly outline the following key requirements for implementation across all operations:\n1. Universal Authority: Every individual has the right and responsibility to stop work when unsafe conditions or behaviours are\nobserved.\n2. No Retaliation: Personnel who exercise SWA in good faith should be protected from any form of disciplinary action or retaliation.\n3. Immediate Response: Work should be stopped immediately upon identification of a hazard, and the issue should be reported\nwithout delay.\n4. Assessment & Resolution: The hazard should be assessed, corrective actions taken, and the situation resolved before work\nresumes.\n5. Training: All personnel should receive training on the SWA policy during induction and through ongoing safety briefings.\n6. Leadership Support: Managers should actively support and promote the SWA policy to foster a strong and proactive safety culture.\nStop Work Authority (SWA)\nThe SMS should include a Stop Work Authority (SWA) policy and procedure. SWA recognizes the importance of encouraging any\nemployee on board a vessel to express concern if they believe that an operation is being incorrectly undertaken or unsafe. SWA\ngives crewmembers the responsibility and obligation to intervene and stop work if they see something unsafe that may cause\nan accident.\nA typical SWA is comprised of six steps:\nStop – When you or a colleague perceive condition(s) or behaviour(s) that pose imminent danger to person(s), equipment, or the\nenvironment, they must immediately initiate a stop work intervention with the person(s) potentially at risk.\nNotify – Notify affected personnel and supervision of the stop work action.\nInvestigate – Affected personnel will discuss the situation and come to an agreement on the stop work action.\nCorrect – The affected area(s) will then be inspected by qualified experts to verify completeness of the modifications and ensure\nall safety issues have been properly resolved.\nResume – All affected personnel will be notified of what corrective actions were implemented, and the affected area(s) will be\nreopened for work by personnel with restart authority.\nFollow-up – The Safety Manager will publish the incident details regarding the stop work action to all Operations Managers and\nemployees, outlining the issue, corrective action, and lessons learned.\nToolbox talk\nA toolbox talk before the work begins is key in ensuring that all workers involved in the work understand and are aware of any\nhazards and their associated risks.\nA toolbox talk is another form of risk assessment carried out in support of a Task -Based-Risk assessment (TBRA). Its prime\npurpose is to talk through the procedures of the job in hand and the findings of the TBRA with the seafarers involved.\nA task-based risk assessment (TBRA) is a systematic approach to identify, evaluate, and control hazards associated with\nspecific tasks or activities in the workplace. It focuses on the individual steps or stages of a task to pinpoint potential hazards\nand implement targeted safety measures.\nWhen carrying out a toolbox talk, it is important to actively involve workers doing the work and others who may be at risk; in\nother words, seafarers, sub-contractors and others on board ship who may be affected. Encourage full and active participation\nand discuss any questions or concerns. Once finished, confirm that everyone fully understands their role in the task and\nthe precautions in place (this is known as ‘closed-loop communication’). Record this along with details of any relevant risk\nassessment to which you have referred.\nGive a toolbox talk before any work is carried out that involves more than one person and where there is significant risk to\npersons or assets.\n(CPSWP 2025)\nIntegrating LOTO with the Permit to Work (PTW) System\nTo ensure the highest level of safety when working with hazardous energy sources, or within spaces containing such sources,\nit is essential to integrate Lockout/Tagout (LOTO) with the Permit to Work (PTW) system. When these systems operate\nindependently, critical safety gaps can arise, such as work commencing before energy sources are fully isolated.\nKey Benefits of Integration:\n1. Ensures all hazardous energy sources are locked out before work begins.\n2. Provides a single, unified workflow for managing high-risk tasks.\n3. Enhances accountability, traceability, and regulatory compliance.\n4. Reduces the risk of human error and miscommunication.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.9","internal_question_no":"04A.009","question_sort_key":4100900.051,"question_text":"Is there a schedule of drills and exercises to address potential emergency shipboard situations and is it being conducted effectively?","guide_to_inspection":"ISM requirement:\n“The company should identify potential emergency shipboard situations and establish procedures to respond to them. The\ncompany should establish programs for drills and exercises to prepare for emergency actions”.\n(ISM Code and Guidelines on the Implementation of the ISM Code, 2010)\nEmergency procedures should at least include collision, grounding, flooding, heavy weather damage, cargo damage,\nshift of cargo, loss of cargo, structural failure as per MSC Circ. 1143, fire (on deck and in cargo hold, the engine room and\naccommodation), damage to fixed and floating objects, explosion, pollution by harmful substances in packaged form, critical\nmachinery failure, rescue from enclosed spaces, serious personal injury, emergency towing equipment, helicopter operations\nand pollution clean-up and emergency operation of hatch cover.\nSOLAS requirement:\nOn-board training in the use of the ship’s fire-extinguishing systems and appliances shall be planned and conducted in\naccordance with the provisions of regulation SOLAS III/19.4.1. 2.2.5\nFire drills shall be conducted and recorded in accordance with the provisions of regulations SOLAS III/19.3 and III/19.5.\nAbandon ship drill: Each lifeboat shall be launched with its assigned operating crew aboard and manoeuvred in the water at\nleast once every three months during an abandon ship drill.\nFree fall lifeboat: In the case of a lifeboat arranged for free-fall launching, at least once every three months during an\nabandon ship drill the crew shall board the lifeboat, properly secure themselves in their seats and commence launch\nprocedures up to but not including the actual release of the lifeboat (i.e., the release hook shall not be released). The lifeboat\nshall then either be free-fall launched with only the required operating crew on board or lowered into the water by means of\nthe secondary means of launching with or without the operating crew on board. In both cases the lifeboat shall thereafter\nbe manoeuvred in the water by the operating crew. At intervals of not more than six months, the lifeboat shall either be\nlaunched by free-fall with only the operating crew on board, or simulated launching shall be carried out in accordance with\nthe guidelines developed by the Organization.\nMuster lists and emergency instructions shall be exhibited in conspicuous places throughout the ship, including the\nnavigation bridge, engine-room, and crew accommodation spaces.\nThe muster list shall specify details of the general emergency alarm and public address system, and action to be taken by\ncrew and passengers when this alarm is sounded. The muster list shall also specify how the order to abandon ship will be\ngiven.\nThe muster list shall specify which officers are assigned to ensure that lifesaving and fire appliances are maintained in good\ncondition and are ready for immediate use.\nThe muster list shall specify substitutes for key persons who may become disabled.\nThe muster list shall be prepared before the ship proceeds to sea.\nThe muster list shall show the duties assigned to the different members of the crew including:\n> Closing of the watertight doors, fire doors, valves, scuppers, side scuttles, skylights, portholes, and other similar openingsin\nthe ship\n> Equipping of the survival craft and other life-saving appliances\n> Preparation and launching of survival craft.\n> General preparations of other life-saving appliances\n> Muster of passengers\n> Use of communication equipment\n> Manning of fire parties assigned to deal with fires\n> Special duties assigned in respect to the use of fire-fighting equipment and installations.\n> Illustrations and instructions in appropriate languages shall be posted in cabins and be conspicuously displayed at muster\nstations and other spaces to inform crew of:\n> Their muster station.\n> The essential actions they must take in an emergency, and\n> The method of donning lifejackets.\nRescue boat drill: As far as is reasonable and practicable, rescue boats other than lifeboats which are also rescue boats, shall be\nlaunched each month with their assigned crew aboard and manoeuvred in the water. In all cases this requirement shall be complied\nwith at least once every three months.\nOn-board training in the use of davit-launched life rafts shall take place at intervals of not more than four months on every ship\nfitted with such appliances. Whenever practicable this shall include the inflation and lowering of a life raft. This life raft may be a\nspecial life raft intended for training purposes only, which is not part of the ship’s life-saving equipment; such a special life raft shall\nbe conspicuously marked.\nSteering gear testing and drills: 1- Within 12 hours before departure, the ship’s steering gear shall be checked and tested by\nthe ship’s crew. 2- All ships’ officers concerned with the operation and/or maintenance of steering gear shall be familiar with\nthe operation of the steering systems fitted on the ship and with the procedures for changing from one system to another.3-\nEmergency steering drill shall take place at least every once every three months in order to practice emergency steering procedure.\n(SOLAS 74,2020)\nMuster lists and emergency instructions shall be exhibited in conspicuous places throughout the ship, including the\nnavigation bridge, engine-room, and crew accommodation spaces.\nThe muster list shall specify details of the general emergency alarm and public address system, and action to be taken by\ncrew and passengers when this alarm is sounded. The muster list shall also specify how the order to abandon ship will be\ngiven.\nThe muster list shall specify which officers are assigned to ensure that lifesaving and fire appliances are maintained in good\ncondition and are ready for immediate use.\nThe muster list shall specify substitutes for key persons who may become disabled.\nThe muster list shall be prepared before the ship proceeds to sea.\nThe muster list shall show the duties assigned to the different members of the crew including:\n> Closing of the watertight doors, fire doors, valves, scuppers, side scuttles, skylights, portholes, and other similar openings\n> in the ship\n> Equipping of the survival craft and other life-saving appliances\n> Preparation and launching of survival craft.\n> General preparations of other life-saving appliances\n> Muster of passengers\n> Use of communication equipment\n> Manning of fire parties assigned to deal with fires\n> Special duties assigned in respect to the use of fire-fighting equipment and installations.\n> Illustrations and instructions in appropriate languages shall be posted in cabins and be conspicuously displayed at\n> muster stations and other spaces to inform crew of:\n> Their muster station.\n> The essential actions they must take in an emergency, and\n> The method of donning lifejackets.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":49,"source_page_end":50,"raw_source_text":"Is there a schedule of drills and exercises to address potential emergency shipboard\nsituations and is it being conducted effectively? (V)\nGuide to Inspection\nISM requirement:\n“The company should identify potential emergency shipboard situations and establish procedures to respond to them. The\ncompany should establish programs for drills and exercises to prepare for emergency actions”.\n(ISM Code and Guidelines on the Implementation of the ISM Code, 2010)\nEmergency procedures should at least include collision, grounding, flooding, heavy weather damage, cargo damage,\nshift of cargo, loss of cargo, structural failure as per MSC Circ. 1143, fire (on deck and in cargo hold, the engine room and\naccommodation), damage to fixed and floating objects, explosion, pollution by harmful substances in packaged form, critical\nmachinery failure, rescue from enclosed spaces, serious personal injury, emergency towing equipment, helicopter operations\nand pollution clean-up and emergency operation of hatch cover.\nSOLAS requirement:\nOn-board training in the use of the ship’s fire-extinguishing systems and appliances shall be planned and conducted in\naccordance with the provisions of regulation SOLAS III/19.4.1. 2.2.5\nFire drills shall be conducted and recorded in accordance with the provisions of regulations SOLAS III/19.3 and III/19.5.\nAbandon ship drill: Each lifeboat shall be launched with its assigned operating crew aboard and manoeuvred in the water at\nleast once every three months during an abandon ship drill.\nFree fall lifeboat: In the case of a lifeboat arranged for free-fall launching, at least once every three months during an\nabandon ship drill the crew shall board the lifeboat, properly secure themselves in their seats and commence launch\nprocedures up to but not including the actual release of the lifeboat (i.e., the release hook shall not be released). The lifeboat\nshall then either be free-fall launched with only the required operating crew on board or lowered into the water by means of\nthe secondary means of launching with or without the operating crew on board. In both cases the lifeboat shall thereafter\nbe manoeuvred in the water by the operating crew. At intervals of not more than six months, the lifeboat shall either be\nlaunched by free-fall with only the operating crew on board, or simulated launching shall be carried out in accordance with\nthe guidelines developed by the Organization.\nMuster lists and emergency instructions shall be exhibited in conspicuous places throughout the ship, including the\nnavigation bridge, engine-room, and crew accommodation spaces.\nThe muster list shall specify details of the general emergency alarm and public address system, and action to be taken by\ncrew and passengers when this alarm is sounded. The muster list shall also specify how the order to abandon ship will be\ngiven.\nThe muster list shall specify which officers are assigned to ensure that lifesaving and fire appliances are maintained in good\ncondition and are ready for immediate use.\nThe muster list shall specify substitutes for key persons who may become disabled.\nThe muster list shall be prepared before the ship proceeds to sea.\nThe muster list shall show the duties assigned to the different members of the crew including:\n> Closing of the watertight doors, fire doors, valves, scuppers, side scuttles, skylights, portholes, and other similar openingsin\nthe ship\n> Equipping of the survival craft and other life-saving appliances\n> Preparation and launching of survival craft.\n> General preparations of other life-saving appliances\n> Muster of passengers\n> Use of communication equipment\n> Manning of fire parties assigned to deal with fires\n> Special duties assigned in respect to the use of fire-fighting equipment and installations.\n> Illustrations and instructions in appropriate languages shall be posted in cabins and be conspicuously displayed at muster\nstations and other spaces to inform crew of:\n> Their muster station.\n> The essential actions they must take in an emergency, and\n> The method of donning lifejackets.\nRescue boat drill: As far as is reasonable and practicable, rescue boats other than lifeboats which are also rescue boats, shall be\nlaunched each month with their assigned crew aboard and manoeuvred in the water. In all cases this requirement shall be complied\nwith at least once every three months.\nOn-board training in the use of davit-launched life rafts shall take place at intervals of not more than four months on every ship\nfitted with such appliances. Whenever practicable this shall include the inflation and lowering of a life raft. This life raft may be a\nspecial life raft intended for training purposes only, which is not part of the ship’s life-saving equipment; such a special life raft shall\nbe conspicuously marked.\nSteering gear testing and drills: 1- Within 12 hours before departure, the ship’s steering gear shall be checked and tested by\nthe ship’s crew. 2- All ships’ officers concerned with the operation and/or maintenance of steering gear shall be familiar with\nthe operation of the steering systems fitted on the ship and with the procedures for changing from one system to another.3-\nEmergency steering drill shall take place at least every once every three months in order to practice emergency steering procedure.\n(SOLAS 74,2020)\nMuster lists and emergency instructions shall be exhibited in conspicuous places throughout the ship, including the\nnavigation bridge, engine-room, and crew accommodation spaces.\nThe muster list shall specify details of the general emergency alarm and public address system, and action to be taken by\ncrew and passengers when this alarm is sounded. The muster list shall also specify how the order to abandon ship will be\ngiven.\nThe muster list shall specify which officers are assigned to ensure that lifesaving and fire appliances are maintained in good\ncondition and are ready for immediate use.\nThe muster list shall specify substitutes for key persons who may become disabled.\nThe muster list shall be prepared before the ship proceeds to sea.\nThe muster list shall show the duties assigned to the different members of the crew including:\n> Closing of the watertight doors, fire doors, valves, scuppers, side scuttles, skylights, portholes, and other similar openings\n> in the ship\n> Equipping of the survival craft and other life-saving appliances\n> Preparation and launching of survival craft.\n> General preparations of other life-saving appliances\n> Muster of passengers\n> Use of communication equipment\n> Manning of fire parties assigned to deal with fires\n> Special duties assigned in respect to the use of fire-fighting equipment and installations.\n> Illustrations and instructions in appropriate languages shall be posted in cabins and be conspicuously displayed at\n> muster stations and other spaces to inform crew of:\n> Their muster station.\n> The essential actions they must take in an emergency, and\n> The method of donning lifejackets.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.10","internal_question_no":"04A.010","question_sort_key":4101000.052,"question_text":"Are procedures for reporting, investigating, and closing out non-conformities, incidents, and hazardous situations available and being followed and, is an incident investigation report or a summarised lessons learned bulletin available for each reported incident?","guide_to_inspection":"Inspector shall verify the incident history of the vessel with the 24-month incident history provided by RightShip. Any\nincidents that are not documented in the RightShip record shall be recorded as a Finding. Record in the comments the\nnumber of near-miss reports submitted by the vessel over the past 12 months.\nThe SMS should include procedures ensuring that non-conformities,incidents, and hazardous situations are reported to the\ncompany, investigated and analysed with the objective of improving safety and pollution prevention.\n(ISM Code and Guidelines on the Implementation of the ISM code, 2010)\nThe inspector should review the records of reported incidents from the past 12 months and verify whether an incident\ninvestigation report or a lessons learned bulletin has been provided by the vessel’s manager for each case where the\nmanager has declared the investigation as completed.\nNear-miss:\nA near-miss is defined as a sequence of events and/or conditions that could have resulted in a loss, but where the outcome\nwas avoided purely by chance or an unplanned interruption in the chain of events.\nPotential losses may include personal injury, environmental harm, or adverse business impacts such as repair or replacement\ncosts, scheduling delays, contractual breaches, or reputational damage.\nUnder the Hazardous Occurrences provisions of the ISM Code, companies are required to investigate near-misses as part of\ntheir regulatory obligations.\nVessel’s managers should actively encourage the reporting of near-misses to support ongoing safety awareness and\ncontinuous improvement.\n(MSC-MEPC.7/Circ.7)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":50,"source_page_end":50,"raw_source_text":"Are procedures for reporting, investigating, and closing out non-conformities, incidents, and hazardous situations\navailable and being followed and, is an incident investigation report or a summarised lessons learned bulletin\navailable for each reported incident? (V)\nGuide to Inspection\nInspector shall verify the incident history of the vessel with the 24-month incident history provided by RightShip. Any\nincidents that are not documented in the RightShip record shall be recorded as a Finding. Record in the comments the\nnumber of near-miss reports submitted by the vessel over the past 12 months.\nThe SMS should include procedures ensuring that non-conformities,incidents, and hazardous situations are reported to the\ncompany, investigated and analysed with the objective of improving safety and pollution prevention.\n(ISM Code and Guidelines on the Implementation of the ISM code, 2010)\nThe inspector should review the records of reported incidents from the past 12 months and verify whether an incident\ninvestigation report or a lessons learned bulletin has been provided by the vessel’s manager for each case where the\nmanager has declared the investigation as completed.\nNear-miss:\nA near-miss is defined as a sequence of events and/or conditions that could have resulted in a loss, but where the outcome\nwas avoided purely by chance or an unplanned interruption in the chain of events.\nPotential losses may include personal injury, environmental harm, or adverse business impacts such as repair or replacement\ncosts, scheduling delays, contractual breaches, or reputational damage.\nUnder the Hazardous Occurrences provisions of the ISM Code, companies are required to investigate near-misses as part of\ntheir regulatory obligations.\nVessel’s managers should actively encourage the reporting of near-misses to support ongoing safety awareness and\ncontinuous improvement.\n(MSC-MEPC.7/Circ.7)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.11","internal_question_no":"04A.011","question_sort_key":4101100.053,"question_text":"Has a PPE Matrix for use of personal protective equipment been provided and is it being worn as required?","guide_to_inspection":"RightShip recommends that ship’s crew use an inertia reel personal fall arrestor with a full body harness when working aloft or over side.\nRecord a Finding if the vessel is not equipped with a safety harness and fall protection device, or if wearing such personal protective\nequipment is not an obligatory requirement under the SMS when operating aloft or overside. Fall protection devices should be\ninspected every twelve months or after a fall. This inspection must be done in accordance with the manufacturer’s instructions by a\ncompetent person. EN 365 specifies the minimum general requirements for instructions for use, maintenance, periodic examination,\nrepair, marking, and packaging of PPE, which includes body holding devices and other equipment used in conjunction with a body\nholding device to prevent falls, for access, egress, and work positioning, to arrest falls, and for rescue.\n“The company must ensure that seafarers are provided with suitable PPE where it is needed. The company should assess the\nequipment required to ensure that it is suitable and effective for the task in question and meets the appropriate standards of design\nand manufacture.” All personnel who are working at height (i.e. in any position from which there is a risk of falling) shall wear a safety\nharness (or belt with shock absorber) attached to a lifeline.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nIMSBC requirements:\nMany bulk cargoes are dusty. The effects of breathing dust can never be beneficial and are probably harmful in some cases at least.\nWhere possible it is always best to avoid exposure to cargo dust and employers and their representatives have a duty to minimise dust.\nWhen exposure to hazardous solids, liquids or gases cannot be avoided respiratory protective equipment (RPE) and safety goggles\nmust be worn.\nThe selection and use of the appropriate PPE is complex and extremely important. It should be part of the risk assessment process.\nFor general shipboard use a simple respirator with a disposable filter where the wearer’s lungs are used to draw air through the filter\nshould be suitable for cargoes which are not stated to be hazardous.\nFilters should be renewed according to manufacturers’ instructions or, in the absence of instructions, when soiled.\nWhen a chemical product and/or other specialist equipment is used during cargo hold cleaning process, full and correct PPE, suitable\nfor the nature of the task must be available and worn at all times throughout the cargo hold cleaning.\n(Guidance on Preparing Cargo Holds and Loading of Solid Bulk Cargoes, 2014)\nThe minimum PPE requirement when rigging a combination pilot ladder overside shall be incorporated into the guideline.\nEmployees working in areas where there are potential electrical hazards shall be provided with, and shall use, electrical protective\nequipment that is appropriate for the specific parts of the body to be protected and for the work to be performed.29 CFR 1910.137\noutlines the design, in-service care, and use regulations for electrical protection equipment, which includes rubber insulating gloves.\nVarious international standards specify requirements for safety helmets. While these standards may differ in certain details,\nthey all share the common goal of ensuring adequate head protection for their intended applications. It is essential to follow the\nmanufacturer’s instructions and to replace helmets after any significant impact or when they no longer meet the required safety\nstandards.\nPPE for Ships Using Ammonia as Fuel\n20.3 Protective equipment\n20.3.1 Suitable protective equipment, including eye protection, to a recognized national or international standard, should be provided\nfor the protection of crew members engaged in normal operations related to\nthe ammonia fuel system.\n20.3.2 Personal protective and safety equipment required in this chapter should be kept in suitable, clearly marked lockers located in\nreadily accessible places.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":51,"source_page_end":51,"raw_source_text":"Has a PPE Matrix for use of personal protective equipment been provided and is it being worn as required? (V)\nGuide to Inspection\nRightShip recommends that ship’s crew use an inertia reel personal fall arrestor with a full body harness when working aloft or over side.\nRecord a Finding if the vessel is not equipped with a safety harness and fall protection device, or if wearing such personal protective\nequipment is not an obligatory requirement under the SMS when operating aloft or overside. Fall protection devices should be\ninspected every twelve months or after a fall. This inspection must be done in accordance with the manufacturer’s instructions by a\ncompetent person. EN 365 specifies the minimum general requirements for instructions for use, maintenance, periodic examination,\nrepair, marking, and packaging of PPE, which includes body holding devices and other equipment used in conjunction with a body\nholding device to prevent falls, for access, egress, and work positioning, to arrest falls, and for rescue.\n“The company must ensure that seafarers are provided with suitable PPE where it is needed. The company should assess the\nequipment required to ensure that it is suitable and effective for the task in question and meets the appropriate standards of design\nand manufacture.” All personnel who are working at height (i.e. in any position from which there is a risk of falling) shall wear a safety\nharness (or belt with shock absorber) attached to a lifeline.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nIMSBC requirements:\nMany bulk cargoes are dusty. The effects of breathing dust can never be beneficial and are probably harmful in some cases at least.\nWhere possible it is always best to avoid exposure to cargo dust and employers and their representatives have a duty to minimise dust.\nWhen exposure to hazardous solids, liquids or gases cannot be avoided respiratory protective equipment (RPE) and safety goggles\nmust be worn.\nThe selection and use of the appropriate PPE is complex and extremely important. It should be part of the risk assessment process.\nFor general shipboard use a simple respirator with a disposable filter where the wearer’s lungs are used to draw air through the filter\nshould be suitable for cargoes which are not stated to be hazardous.\nFilters should be renewed according to manufacturers’ instructions or, in the absence of instructions, when soiled.\nWhen a chemical product and/or other specialist equipment is used during cargo hold cleaning process, full and correct PPE, suitable\nfor the nature of the task must be available and worn at all times throughout the cargo hold cleaning.\n(Guidance on Preparing Cargo Holds and Loading of Solid Bulk Cargoes, 2014)\nThe minimum PPE requirement when rigging a combination pilot ladder overside shall be incorporated into the guideline.\nEmployees working in areas where there are potential electrical hazards shall be provided with, and shall use, electrical protective\nequipment that is appropriate for the specific parts of the body to be protected and for the work to be performed.29 CFR 1910.137\noutlines the design, in-service care, and use regulations for electrical protection equipment, which includes rubber insulating gloves.\nVarious international standards specify requirements for safety helmets. While these standards may differ in certain details,\nthey all share the common goal of ensuring adequate head protection for their intended applications. It is essential to follow the\nmanufacturer’s instructions and to replace helmets after any significant impact or when they no longer meet the required safety\nstandards.\nPPE for Ships Using Ammonia as Fuel\n20.3 Protective equipment\n20.3.1 Suitable protective equipment, including eye protection, to a recognized national or international standard, should be provided\nfor the protection of crew members engaged in normal operations related to\nthe ammonia fuel system.\n20.3.2 Personal protective and safety equipment required in this chapter should be kept in suitable, clearly marked lockers located in\nreadily accessible places.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.12","internal_question_no":"04A.012","question_sort_key":4101200.054,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":51,"source_page_end":51,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.13","internal_question_no":"04A.013","question_sort_key":4101300.055,"question_text":"Is a completed IMSBC/BLU Code ship/shore safety checklist for loading and unloading dry bulk carriers available and are the requirements of the checklist complied with?","guide_to_inspection":"Incomplete ship/shore safety checklist and/or non-compliance with the checklist should be recorded as a Finding.\nThe purpose of the ship/shore safety checklist is to improve working relationships between ship and terminal, and thereby to\nimprove the safety of operations. Misunderstandings occur and mistakes can be made when ships’ officers do not understand\nthe intentions of the terminal personnel, and the same applies when terminal personnel do not understand what the ship can\nand cannot safely do.\n(BLU Code, 2011)\nFor vessel fitted with gantry cranes following should be discussed during the meeting and documented in the ship/shore safety\ncheck list:\n1. The time required for preparation before operations and securing after completion of cargo operation considered in the ship\nshore safety checks and information exchanged.\n2. Operations limits of gantry as per makers manual established (including maximum weather conditions & visibility and ships\nlist/trim) and this information made available to the operator.\n3. Blind areas for operator, if any, identified and measures in place for supervision and signalling arranged. Special consideration\nwhen operating within shore structures / obstructions or in tandem with shore cranes.\nWhen stevedores are working on board the vessel, the ship-shore safety checklist should be shared with them. Both the\nstevedore and the master’s representative are responsible for ensuring full compliance with the checklist, including Item 13 of\nthe BLU (Bulk Loading/Unloading) ship-shore safety checklist. This is essential to maintain a safe atmosphere within the cargo\nholds and access points at all times while stevedores and other personnel are present in these compartments.\nAccess hatches to enclosed spaces should remain locked while stevedores are working on board. This measure is essential to\nprevent unauthorized and unsupervised entry into cargo hold access areas, thereby ensuring the safety of all personnel.\nEffective access control to cargo holds and enclosed spaces—whether through physical barriers or robust entry procedures that\nrestrict easy access—should be firmly established and maintained.\nThe ship-shore safety checklists should include a stevedore familiarisation section with emergency procedures.\nThe ship-shore checklist should verify compliance with cargo hold entry procedures at least once every watch.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":52,"source_page_end":52,"raw_source_text":"Is a completed IMSBC/BLU Code ship/shore safety checklist for loading and unloading dry bulk carriers\navailable and are the requirements of the checklist complied with? (M)\nGuide to Inspection\nIncomplete ship/shore safety checklist and/or non-compliance with the checklist should be recorded as a Finding.\nThe purpose of the ship/shore safety checklist is to improve working relationships between ship and terminal, and thereby to\nimprove the safety of operations. Misunderstandings occur and mistakes can be made when ships’ officers do not understand\nthe intentions of the terminal personnel, and the same applies when terminal personnel do not understand what the ship can\nand cannot safely do.\n(BLU Code, 2011)\nFor vessel fitted with gantry cranes following should be discussed during the meeting and documented in the ship/shore safety\ncheck list:\n1. The time required for preparation before operations and securing after completion of cargo operation considered in the ship\nshore safety checks and information exchanged.\n2. Operations limits of gantry as per makers manual established (including maximum weather conditions & visibility and ships\nlist/trim) and this information made available to the operator.\n3. Blind areas for operator, if any, identified and measures in place for supervision and signalling arranged. Special consideration\nwhen operating within shore structures / obstructions or in tandem with shore cranes.\nWhen stevedores are working on board the vessel, the ship-shore safety checklist should be shared with them. Both the\nstevedore and the master’s representative are responsible for ensuring full compliance with the checklist, including Item 13 of\nthe BLU (Bulk Loading/Unloading) ship-shore safety checklist. This is essential to maintain a safe atmosphere within the cargo\nholds and access points at all times while stevedores and other personnel are present in these compartments.\nAccess hatches to enclosed spaces should remain locked while stevedores are working on board. This measure is essential to\nprevent unauthorized and unsupervised entry into cargo hold access areas, thereby ensuring the safety of all personnel.\nEffective access control to cargo holds and enclosed spaces—whether through physical barriers or robust entry procedures that\nrestrict easy access—should be firmly established and maintained.\nThe ship-shore safety checklists should include a stevedore familiarisation section with emergency procedures.\nThe ship-shore checklist should verify compliance with cargo hold entry procedures at least once every watch.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.14","internal_question_no":"04A.014","question_sort_key":4101400.056,"question_text":"Are Water Ingress Detector System(WIDS) and alarms maintained in good condition and are the records of tests being maintained?","guide_to_inspection":"If the vessel is classified as a General Cargo Ship according to the Class certificate,the response to this question should be\nN/A.\n> Bulk carriers shall be fitted with water level detector\n> In each cargo hold, giving audible and visual alarms, one when the water level above the inner bottom in any hold\nreaches a height of 0.5m and another at a height not less than 15% of the depth of the cargo hold but not more than 2.0\nm. On bulk carriers to which regulation 9.2 applies, only the latter alarm need be installed. The water level detectors shall\nbe fitted in the aft end of the cargo holds. For cargo holds which are used for water ballast, an alarm overriding device\nmay be installed. The visual alarms shall clearly discriminate between the two different level detectors in each hold.\n> In any ballast tank forward of the collision bulkhead required by regulation II-1/11, giving an audible and visual alarm\nwhen the liquid in the tank reaches a level not exceeding 10% of the tank capacity. An alarm overriding device may be\ninstalled to be activated when the tank is in use; and\n> In any dry or void space other than a chain cable locker, any part of which extends forward of the foremost cargo\nhold, giving an audible and visual alarm at a water level of 0.1 m above the deck. Such alarms need not be provided in\nenclosed spaces the volume of which does not exceed 0.1% of the ship’s maximum displacement volume.\n> The audible and visual alarms specified in paragraph 1 shall be located on the navigation bridge.\n> The record of testing of alarm systems should be retained on board.\n> The electrical power supply should be from two separate sources, one should be the main source of electrical power\nand the other should be the emergency source, unless a continuously charged dedicated accumulator battery is fitted,\nhaving arrangement, location and endurance equivalent to that of the emergency source (18 hours). The battery supply\nmay be an internal battery in the water level detector system.\n> The changeover arrangement of supply from one electrical source to another need not be integrated into the water level\ndetector system.\n> Where batteries are used for the secondary power supply, failure alarms for both power supplies should be provided.\n(SOLAS 74,2020)\n(Resolution MSC. 188 (79)/Performance Standard for Water Level Detectors 2004)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":52,"source_page_end":52,"raw_source_text":"Are Water Ingress Detector System(WIDS) and alarms maintained in good condition and are the records\nof tests being maintained? (V & M)\nGuide to Inspection\nIf the vessel is classified as a General Cargo Ship according to the Class certificate,the response to this question should be\nN/A.\n> Bulk carriers shall be fitted with water level detector\n> In each cargo hold, giving audible and visual alarms, one when the water level above the inner bottom in any hold\nreaches a height of 0.5m and another at a height not less than 15% of the depth of the cargo hold but not more than 2.0\nm. On bulk carriers to which regulation 9.2 applies, only the latter alarm need be installed. The water level detectors shall\nbe fitted in the aft end of the cargo holds. For cargo holds which are used for water ballast, an alarm overriding device\nmay be installed. The visual alarms shall clearly discriminate between the two different level detectors in each hold.\n> In any ballast tank forward of the collision bulkhead required by regulation II-1/11, giving an audible and visual alarm\nwhen the liquid in the tank reaches a level not exceeding 10% of the tank capacity. An alarm overriding device may be\ninstalled to be activated when the tank is in use; and\n> In any dry or void space other than a chain cable locker, any part of which extends forward of the foremost cargo\nhold, giving an audible and visual alarm at a water level of 0.1 m above the deck. Such alarms need not be provided in\nenclosed spaces the volume of which does not exceed 0.1% of the ship’s maximum displacement volume.\n> The audible and visual alarms specified in paragraph 1 shall be located on the navigation bridge.\n> The record of testing of alarm systems should be retained on board.\n> The electrical power supply should be from two separate sources, one should be the main source of electrical power\nand the other should be the emergency source, unless a continuously charged dedicated accumulator battery is fitted,\nhaving arrangement, location and endurance equivalent to that of the emergency source (18 hours). The battery supply\nmay be an internal battery in the water level detector system.\n> The changeover arrangement of supply from one electrical source to another need not be integrated into the water level\ndetector system.\n> Where batteries are used for the secondary power supply, failure alarms for both power supplies should be provided.\n(SOLAS 74,2020)\n(Resolution MSC. 188 (79)/Performance Standard for Water Level Detectors 2004)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.15","internal_question_no":"04A.015","question_sort_key":4101500.057,"question_text":"Has a smoking policy been implemented; is it being followed and are designated smoking areas adequately identified?","guide_to_inspection":"Environmental Tobacco Smoke (ETS) is a substantial health risk to nonsmokers. There is no degree of exposure to ETS\nthat is considered safe. Passive smoking entails the inhalation of ETS. ETS is a complex mixture of chemicals and particles\n(particulate matter) that is released into the air when a person smokes a cigarette, cigar, or pipe. Nonsmokers may face a\nvariety of adverse health consequences as a result of ETS.\n(Guidance Note on the Elimination of Environmental Tobacco Smoke in the Workplace, 2003)\nEmployers have a responsibility to ensure the health and safety of their employees and other persons on board ship, to the\nextent that this is reasonably practicable.\nRightShip urges the vessel’s manager to implement a smoking policy with the following objectives:\n> to promote the health and welfare of seafarers;\n> to provide and maintain a healthy shipboard environment;\n> to minimise the risks of tobacco smoke to non-smokers;\n> to educate seafarers about the harmful effects of smoking; and\n> to provide support and assistance to any seafarers who smoke and express a desire to quit.\nControl methods that should be considered include the following:\n> Restriction of smoking locations to protect non-smoking personnel from ETS and to provide specified safe smoking\nareas for smokers during their off-duty hours.\n> Smoking should be permitted only in designated places, with visible instructions and prohibition notices.\n> Any room allocated for smoking should be utilised only for that purpose. It is not suggested that smoking be permitted\nin the cabins.\n> Where reasonably practicable, any room that is designated for smoking should be adequately ventilated and not\nventilated into a smoke-free place.\n> Smoking should be prohibited in kitchens, galleys, pantries, storerooms or other places where food is stored, handled or\nprepared and notices to this effect should be displayed.\n> Careless disposal of burning matches and cigarette ends is dangerous: ashtrays, or other suitable containers, should be\nprovided and used in locations where smoking is permitted.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":53,"source_page_end":53,"raw_source_text":"Has a smoking policy been implemented; is it being followed and are designated smoking areas\nadequately identified? (V)\nGuide to Inspection\nEnvironmental Tobacco Smoke (ETS) is a substantial health risk to nonsmokers. There is no degree of exposure to ETS\nthat is considered safe. Passive smoking entails the inhalation of ETS. ETS is a complex mixture of chemicals and particles\n(particulate matter) that is released into the air when a person smokes a cigarette, cigar, or pipe. Nonsmokers may face a\nvariety of adverse health consequences as a result of ETS.\n(Guidance Note on the Elimination of Environmental Tobacco Smoke in the Workplace, 2003)\nEmployers have a responsibility to ensure the health and safety of their employees and other persons on board ship, to the\nextent that this is reasonably practicable.\nRightShip urges the vessel’s manager to implement a smoking policy with the following objectives:\n> to promote the health and welfare of seafarers;\n> to provide and maintain a healthy shipboard environment;\n> to minimise the risks of tobacco smoke to non-smokers;\n> to educate seafarers about the harmful effects of smoking; and\n> to provide support and assistance to any seafarers who smoke and express a desire to quit.\nControl methods that should be considered include the following:\n> Restriction of smoking locations to protect non-smoking personnel from ETS and to provide specified safe smoking\nareas for smokers during their off-duty hours.\n> Smoking should be permitted only in designated places, with visible instructions and prohibition notices.\n> Any room allocated for smoking should be utilised only for that purpose. It is not suggested that smoking be permitted\nin the cabins.\n> Where reasonably practicable, any room that is designated for smoking should be adequately ventilated and not\nventilated into a smoke-free place.\n> Smoking should be prohibited in kitchens, galleys, pantries, storerooms or other places where food is stored, handled or\nprepared and notices to this effect should be displayed.\n> Careless disposal of burning matches and cigarette ends is dangerous: ashtrays, or other suitable containers, should be\nprovided and used in locations where smoking is permitted.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.16","internal_question_no":"04A.016","question_sort_key":4101600.058,"question_text":"Are portable gas detectors suitable for atmosphere testing of enclosed spaces provided; in good condition; calibrated in accordance with the manufacturer’s instructions, and are officers trained and competent with their operation?","guide_to_inspection":"The SOLAS XI-1/7 regulation requires portable gas detectors to be dedicated 4-gas (oxygen, flammable gases, or vapours (% of\nLFL), carbon monoxide; and hydrogen sulphides), capable of 10 hours continuous operation, waterproof and dustproof to Ingress\nProtection rating IP67, and capable of remote detection (using a pump with a sample hose) suitable to test the atmosphere in an\nenclosed space before entry. Calibration is also a requirement, as prescribed by the manufacturers’ instructions.\n(SOLAS 74,2020)\nThe gas detection equipment should be appropriate for the cargo that the ship has carried and is carrying considering information\nprovided in the shipper’s declaration, the Safety Data Sheets (SDS), the IMDG Code, the IMSBC Code, International Bulk Chemical\nCode (IBC Code) and the IGC Code. The gas detection equipment, including devices for testing CO2, should be capable of operating\ncorrectly even in oxygen-depleted atmosphere.\nAppropriate testing of the atmosphere of a space should be carried out with properly calibrated equipment by persons trained in\nthe use of the equipment. The manufacturers’ instructions should be strictly followed. Testing of the atmosphere of a space should\nbe carried out before any person enters the space and at regular intervals thereafter until all work is completed. Where appropriate,\nthe testing of the atmosphere of a space should be carried out at as many different levels and areas as is necessary to account for\ngas stratification, and obtain a representative sample of the atmosphere in the space. In some cases, it may be difficult to test the\natmosphere throughout the enclosed space without entering the space (e.g. the bottom landing of a stairway or complex areas of\nthe structure within the space) and this should be taken into account.\nAll ships should carry at least two sets of gas detection equipment as required by SOLAS regulation XI-1/7, taking into account\nthe Guidelines to facilitate the selection of portable atmosphere testing instruments for enclosed spaces as required by SOLAS\nregulation XI-1/7 (MSC.1/Circ.1477). Any ship which may carry a cargo capable of generating hazardous vapours and which\nrequires regular entry into the cargo space for cleaning or inspection should carry two sets of gas detection equipment in addition\nto those required by SOLAS regulation XI-1/7 for assessing the risk to personnel entering the space. The use of flexible hoses or\nfixed sampling lines, which reach remote areas within the enclosed space, may allow for safe testing without the need to enter the\nspace.\n(IMO, Resolution MSC.581(110), 2025)\nRightShip recommends that vessels carry a minimum of two portable gas detectors equipped with built-in sample pumps to\nensure accurate and reliable atmosphere testing. Detectors fitted with manual aspiration pumps are acceptable only if supplied by\nthe manufacturer and accompanied by clear, model-specific instructions stating the exact number of strokes required to fully purge\nthe sampling line and deliver a representative sample to the sensor chamber. This is essential, as stroke volume varies significantly\nbetween models; insufficient strokes can result in incomplete sampling, inaccurate readings, and elevated safety risk to personnel.\nBump test is a “qualitative function check where a challenge gas is passed over the sensor(s) at a concentration and exposure time\nsufficient to activate all alarm indicators to present at least their lower alarm setting. This is typically dependent on the response\ntime of the sensor(s) or a minimum level of response achieved, such as 80% of gas concentration applied.” This verifies that\nsensors and alarms are functioning properly; if they are not, a blockage may be present. In conclusion, bump testing examines\nfunction, not accuracy.\nCalibration Check - A quantitative test utilizing a known traceable concentration of test gas to demonstrate that the sensor(s) and\nalarms respond to the gas within manufacturer’s acceptable limits. This is typically ±10-20% of the test gas concentration applied\nunless otherwise specified by the manufacturer, internal company policy, or a regulatory agency.\nFull calibration - The adjustment of the sensor(s) response to match the desired value compared to a known traceable\nconcentration of test gas. This should be done in accordance with the manufacturer’s instructions.\nPersonal gas monitoring equipment is designed for personal use only, to provide a warning against oxygen deficiency, toxic gases\nand explosive atmospheres whilst the wearer is in the space. This equipment should not be used as a means of determining\nwhether a dangerous (enclosed) space is safe prior to entry, unless the specific equipment has the necessary certified/approved\nadditional capability to conduct remote readings (i.e. pumping capability)\n(The merchant shipping and fishing vessels (entry into enclosed spaces) regulations 2022, 2022)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":53,"source_page_end":54,"raw_source_text":"Are portable gas detectors suitable for atmosphere testing of enclosed spaces provided; in good condition;\ncalibrated in accordance with the manufacturer’s instructions, and are officers trained and competent with\ntheir operation? (V & M)\nGuide to Inspection\nThe SOLAS XI-1/7 regulation requires portable gas detectors to be dedicated 4-gas (oxygen, flammable gases, or vapours (% of\nLFL), carbon monoxide; and hydrogen sulphides), capable of 10 hours continuous operation, waterproof and dustproof to Ingress\nProtection rating IP67, and capable of remote detection (using a pump with a sample hose) suitable to test the atmosphere in an\nenclosed space before entry. Calibration is also a requirement, as prescribed by the manufacturers’ instructions.\n(SOLAS 74,2020)\nThe gas detection equipment should be appropriate for the cargo that the ship has carried and is carrying considering information\nprovided in the shipper’s declaration, the Safety Data Sheets (SDS), the IMDG Code, the IMSBC Code, International Bulk Chemical\nCode (IBC Code) and the IGC Code. The gas detection equipment, including devices for testing CO2, should be capable of operating\ncorrectly even in oxygen-depleted atmosphere.\nAppropriate testing of the atmosphere of a space should be carried out with properly calibrated equipment by persons trained in\nthe use of the equipment. The manufacturers’ instructions should be strictly followed. Testing of the atmosphere of a space should\nbe carried out before any person enters the space and at regular intervals thereafter until all work is completed. Where appropriate,\nthe testing of the atmosphere of a space should be carried out at as many different levels and areas as is necessary to account for\ngas stratification, and obtain a representative sample of the atmosphere in the space. In some cases, it may be difficult to test the\natmosphere throughout the enclosed space without entering the space (e.g. the bottom landing of a stairway or complex areas of\nthe structure within the space) and this should be taken into account.\nAll ships should carry at least two sets of gas detection equipment as required by SOLAS regulation XI-1/7, taking into account\nthe Guidelines to facilitate the selection of portable atmosphere testing instruments for enclosed spaces as required by SOLAS\nregulation XI-1/7 (MSC.1/Circ.1477). Any ship which may carry a cargo capable of generating hazardous vapours and which\nrequires regular entry into the cargo space for cleaning or inspection should carry two sets of gas detection equipment in addition\nto those required by SOLAS regulation XI-1/7 for assessing the risk to personnel entering the space. The use of flexible hoses or\nfixed sampling lines, which reach remote areas within the enclosed space, may allow for safe testing without the need to enter the\nspace.\n(IMO, Resolution MSC.581(110), 2025)\nRightShip recommends that vessels carry a minimum of two portable gas detectors equipped with built-in sample pumps to\nensure accurate and reliable atmosphere testing. Detectors fitted with manual aspiration pumps are acceptable only if supplied by\nthe manufacturer and accompanied by clear, model-specific instructions stating the exact number of strokes required to fully purge\nthe sampling line and deliver a representative sample to the sensor chamber. This is essential, as stroke volume varies significantly\nbetween models; insufficient strokes can result in incomplete sampling, inaccurate readings, and elevated safety risk to personnel.\nBump test is a “qualitative function check where a challenge gas is passed over the sensor(s) at a concentration and exposure time\nsufficient to activate all alarm indicators to present at least their lower alarm setting. This is typically dependent on the response\ntime of the sensor(s) or a minimum level of response achieved, such as 80% of gas concentration applied.” This verifies that\nsensors and alarms are functioning properly; if they are not, a blockage may be present. In conclusion, bump testing examines\nfunction, not accuracy.\nCalibration Check - A quantitative test utilizing a known traceable concentration of test gas to demonstrate that the sensor(s) and\nalarms respond to the gas within manufacturer’s acceptable limits. This is typically ±10-20% of the test gas concentration applied\nunless otherwise specified by the manufacturer, internal company policy, or a regulatory agency.\nFull calibration - The adjustment of the sensor(s) response to match the desired value compared to a known traceable\nconcentration of test gas. This should be done in accordance with the manufacturer’s instructions.\nPersonal gas monitoring equipment is designed for personal use only, to provide a warning against oxygen deficiency, toxic gases\nand explosive atmospheres whilst the wearer is in the space. This equipment should not be used as a means of determining\nwhether a dangerous (enclosed) space is safe prior to entry, unless the specific equipment has the necessary certified/approved\nadditional capability to conduct remote readings (i.e. pumping capability)\n(The merchant shipping and fishing vessels (entry into enclosed spaces) regulations 2022, 2022)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.17","internal_question_no":"04A.017","question_sort_key":4101700.059,"question_text":"Is the welding and gas-burning equipment,as well as the electric arc welding equipment, properly stored and maintained in good working order?","guide_to_inspection":"Record a finding if the annual check of the oxygen-acetylene welding equipment/installation on board has not been carried out by a\ncompetent person in accordance with the equipment manufacturer’s guidelines, or if there is no recorded evidence of such a check.\nIn the absence of the manufacturer’s guidelines, such guidelines should be sought from the certified service providers engaged in\nthis service .\nOxy-acetylene gas equipment typically consists of oxygen and acetylene cylinders, pressure regulators, safety devices such as\nnon-return valves and flame arrestors, and a flexible hose assembly capable of supplying a mixed gas output via a blowpipe.\nA pressure regulator should be selected based on the compatibility of the gas. Regulators are designed for a certain gas and must\nnot be used with any other gas once installed in that gas service. Oxygen regulators are intended for use in oxygen service only and\nacetylene regulators are intended for use in acetylene service only. The use of LPG / Propane in gas cutting and welding systems\nare prohibited.\nThe pressure regulator shall be replaced every five years or as indicated by the manufacturer.\nHose tail refers to the end of a coupling device (such as a nipple/nozzle) that is intended to be placed into a hose.\nThe hose shall be crimped to the hose tail using an appropriate crimping instrument that provides reproducible crimping\nperformance. To secure the hose to the hose tail, no worm screw drive or similar detachable clips or clamps shall be utilized.\nHoses shall be constructed from a material compatible with the gas being used. Hoses shall not be utilized for gases or at\npressures greater than those for which they were intended.\n> Hose assemblies shall be permanently labelled with the following information:The manufacturer’s\nname or trademark; and\n> A reference to a recognized international standard, for example EN 1256.\nThis information shall be marked on the mounting device for the hose or on a separate band attached to the hose adjacent to the\ncoupling or on the mounting device.\nWhen a hose’s general condition deteriorates, it must be discarded.\nHoses used with welding equipment are color-coded. Hoses for oxygen should be blue, whereas hoses for acetylene should be red.\nBlowpipes have been referred to as torches, lamps, blowtorches, guns, shanks, burners, and handles.\nEvery five years from the date of manufacture, or as recommended by the manufacturer, the flame arrestor shall be renewed.\nBlowpipes shall be maintained in accordance with the manufacturer’s / supplier’s recommendations.\nPrior to each blowpipe inlet connection, a non-return valve (hose check valve) shall be inserted into the assembled hose. The non-\nreturn valve should be replaced according to the manufacturer’s recommendations.\nCopper pipe or fittings shall not be used to connect acetylene hoses.\nThe pipeline and fittings for oxygen distribution must be made of seamless steel or copper.\nThe hard pipe for oxygen and acetylene must be color coded, with blue piping for oxygen and red piping for acetylene.\n(BS EN 1256:2006 Gas welding equipment. Specification for hose assemblies for equipment for welding, cutting and allied\nprocesses, 2006)\n(Code of Practice 7 The Safe Use of Oxy-Fuel Gas Equipment (individual Portable or Mobile Cylinder Supply), 2018)\n(BS EN 1256:2006 Gas welding equipment. Specification for hose assemblies for equipment for welding, cutting and allied\nprocesses, 2006)\nRegular inspection, thorough examination, and testing of all components to ensure that all the oxy/ acetylene equipment in use on\nboard is in a safe operational condition. This should be performed at least annually by a competent person in accordance with the\nequipment manufacturer’s guidelines. Objective evidence of such tests should be available on board.\nPressure testing of the on-board piping system should be performed by a competent person in accordance with applicable CLASS/\nFLAG rules. An appropriate certificate or service record should be issued.\n(UK P&I club, Technical Bulletin-Oxy/Acetylene equipment, 2008)\nElectric Arc Welding\nWelding Electrocution Risk\nElectric arc welding can cause electrocution due to three main factors:\n> High Open Circuit voltage(OCV): Open Circuit Voltage (OCV), No-Load Voltage, Safety Voltage, etc., indicate the expected\nwelding output voltage when the machine is ON but not actively welding. A high OCV increases the chance of electric shock.\n> Faulty or non-insulated electrode holder: A damaged or non-insulated electrode holder exposes the welder to electrocution\nrisk.\n> Return clamp connected to hull structure: If the welder connects the return clamp to the ship’s structure instead of the\nworkpiece, it increases the risk of getting electrocuted.”\n(Code of Safe Working Practices for Merchant Seafarers , 2024)\nWelding Personal Protective Equipment (PPE) Requirements\n24.4.2 The operator should normally wear:\n> welding shields or welding goggles with appropriate shade of filter lens conforming to EN 169 or to a recognised international\nstandard. (goggles are only recommended for gas welding and flame cutting);\n> leather gauntlets;\n> leather apron (in appropriate circumstances);\n> long-sleeved natural-fibre boiler suit or other approved protective clothing.\n24.4.3 Clothing should be free of grease and oil and other flammable substances.\nWelding Power Source Requirements\n24.6.1 To minimise personal harm from electric shock, electric welding power sources for shipboard use should have a direct\ncurrent (DC) output not exceeding 70 volts, with a minimum ripple. See section 24.6.13 for further information on DC power\nsources.\n24.6.2 When DC equipment is not available, AC output power sources may be used providing:\n> they have an integral voltage-limiting device to ensure that the idling voltage (the voltage between electrode and workpiece\nbefore an arc is struck between them) does not exceed 25 V rms the proper function of the device (which may be affected by\ndust or humidity) is checked each time a welding set is used.\n24.6.3 Some voltage-limiting devices are affected by their angle of tilt from the vertical. Therefore mount and use them in the\nposition specified by the manufacturers. This requirement can be affected by adverse sea conditions.\n24.6.12 Provide a local switching arrangement or other suitable means to rapidly cut off current from the electrode if the operator\ngets into difficulties, and to isolate the holder when changing electrodes.\n24.7.1 In addition to the protective clothing specified in section 24.4.1. the welding operator should wear non-conducting safety\nfootwear complying with BS EN ISO 20345:2012/BS EN 50321-1:2018. or to a recognised international standard. Clothing should\nbe kept as dry as possible as some protection against electric shock; it is particularly important that gloves should be dry because\nwet leather is a good conductor.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":54,"source_page_end":55,"raw_source_text":"Is the welding and gas-burning equipment,as well as the electric arc welding equipment, properly stored\nand maintained in good working order? (V & M)\nGuide to Inspection\nRecord a finding if the annual check of the oxygen-acetylene welding equipment/installation on board has not been carried out by a\ncompetent person in accordance with the equipment manufacturer’s guidelines, or if there is no recorded evidence of such a check.\nIn the absence of the manufacturer’s guidelines, such guidelines should be sought from the certified service providers engaged in\nthis service .\nOxy-acetylene gas equipment typically consists of oxygen and acetylene cylinders, pressure regulators, safety devices such as\nnon-return valves and flame arrestors, and a flexible hose assembly capable of supplying a mixed gas output via a blowpipe.\nA pressure regulator should be selected based on the compatibility of the gas. Regulators are designed for a certain gas and must\nnot be used with any other gas once installed in that gas service. Oxygen regulators are intended for use in oxygen service only and\nacetylene regulators are intended for use in acetylene service only. The use of LPG / Propane in gas cutting and welding systems\nare prohibited.\nThe pressure regulator shall be replaced every five years or as indicated by the manufacturer.\nHose tail refers to the end of a coupling device (such as a nipple/nozzle) that is intended to be placed into a hose.\nThe hose shall be crimped to the hose tail using an appropriate crimping instrument that provides reproducible crimping\nperformance. To secure the hose to the hose tail, no worm screw drive or similar detachable clips or clamps shall be utilized.\nHoses shall be constructed from a material compatible with the gas being used. Hoses shall not be utilized for gases or at\npressures greater than those for which they were intended.\n> Hose assemblies shall be permanently labelled with the following information:The manufacturer’s\nname or trademark; and\n> A reference to a recognized international standard, for example EN 1256.\nThis information shall be marked on the mounting device for the hose or on a separate band attached to the hose adjacent to the\ncoupling or on the mounting device.\nWhen a hose’s general condition deteriorates, it must be discarded.\nHoses used with welding equipment are color-coded. Hoses for oxygen should be blue, whereas hoses for acetylene should be red.\nBlowpipes have been referred to as torches, lamps, blowtorches, guns, shanks, burners, and handles.\nEvery five years from the date of manufacture, or as recommended by the manufacturer, the flame arrestor shall be renewed.\nBlowpipes shall be maintained in accordance with the manufacturer’s / supplier’s recommendations.\nPrior to each blowpipe inlet connection, a non-return valve (hose check valve) shall be inserted into the assembled hose. The non-\nreturn valve should be replaced according to the manufacturer’s recommendations.\nCopper pipe or fittings shall not be used to connect acetylene hoses.\nThe pipeline and fittings for oxygen distribution must be made of seamless steel or copper.\nThe hard pipe for oxygen and acetylene must be color coded, with blue piping for oxygen and red piping for acetylene.\n(BS EN 1256:2006 Gas welding equipment. Specification for hose assemblies for equipment for welding, cutting and allied\nprocesses, 2006)\n(Code of Practice 7 The Safe Use of Oxy-Fuel Gas Equipment (individual Portable or Mobile Cylinder Supply), 2018)\n(BS EN 1256:2006 Gas welding equipment. Specification for hose assemblies for equipment for welding, cutting and allied\nprocesses, 2006)\nRegular inspection, thorough examination, and testing of all components to ensure that all the oxy/ acetylene equipment in use on\nboard is in a safe operational condition. This should be performed at least annually by a competent person in accordance with the\nequipment manufacturer’s guidelines. Objective evidence of such tests should be available on board.\nPressure testing of the on-board piping system should be performed by a competent person in accordance with applicable CLASS/\nFLAG rules. An appropriate certificate or service record should be issued.\n(UK P&I club, Technical Bulletin-Oxy/Acetylene equipment, 2008)\nElectric Arc Welding\nWelding Electrocution Risk\nElectric arc welding can cause electrocution due to three main factors:\n> High Open Circuit voltage(OCV): Open Circuit Voltage (OCV), No-Load Voltage, Safety Voltage, etc., indicate the expected\nwelding output voltage when the machine is ON but not actively welding. A high OCV increases the chance of electric shock.\n> Faulty or non-insulated electrode holder: A damaged or non-insulated electrode holder exposes the welder to electrocution\nrisk.\n> Return clamp connected to hull structure: If the welder connects the return clamp to the ship’s structure instead of the\nworkpiece, it increases the risk of getting electrocuted.”\n(Code of Safe Working Practices for Merchant Seafarers , 2024)\nWelding Personal Protective Equipment (PPE) Requirements\n24.4.2 The operator should normally wear:\n> welding shields or welding goggles with appropriate shade of filter lens conforming to EN 169 or to a recognised international\nstandard. (goggles are only recommended for gas welding and flame cutting);\n> leather gauntlets;\n> leather apron (in appropriate circumstances);\n> long-sleeved natural-fibre boiler suit or other approved protective clothing.\n24.4.3 Clothing should be free of grease and oil and other flammable substances.\nWelding Power Source Requirements\n24.6.1 To minimise personal harm from electric shock, electric welding power sources for shipboard use should have a direct\ncurrent (DC) output not exceeding 70 volts, with a minimum ripple. See section 24.6.13 for further information on DC power\nsources.\n24.6.2 When DC equipment is not available, AC output power sources may be used providing:\n> they have an integral voltage-limiting device to ensure that the idling voltage (the voltage between electrode and workpiece\nbefore an arc is struck between them) does not exceed 25 V rms the proper function of the device (which may be affected by\ndust or humidity) is checked each time a welding set is used.\n24.6.3 Some voltage-limiting devices are affected by their angle of tilt from the vertical. Therefore mount and use them in the\nposition specified by the manufacturers. This requirement can be affected by adverse sea conditions.\n24.6.12 Provide a local switching arrangement or other suitable means to rapidly cut off current from the electrode if the operator\ngets into difficulties, and to isolate the holder when changing electrodes.\n24.7.1 In addition to the protective clothing specified in section 24.4.1. the welding operator should wear non-conducting safety\nfootwear complying with BS EN ISO 20345:2012/BS EN 50321-1:2018. or to a recognised international standard. Clothing should\nbe kept as dry as possible as some protection against electric shock; it is particularly important that gloves should be dry because\nwet leather is a good conductor.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.18","internal_question_no":"04A.018","question_sort_key":4101800.06,"question_text":"Are the lifeboats, rescue boat and davit-launched life raft their equipment and launching arrangements serviced periodically in good condition, and are the crew familiar with the launching procedure and operation?","guide_to_inspection":"When the vessel is equipped with a davit-launched life raft, the inspector shall check the crew’s familiarity with the operation of the\ndavit and test its operation.\nWire rope slings and pendants are occasionally sheathed in plastic by the manufacturer. This sheathing allows saltwater ingress,\nwhich aids corrosion by retaining moisture and prevents external inspection and the application of lubricant or other corrosion-\ninhibiting substances.\nThe vessel’s managers should establish a procedure for the regular inspection and maintenance of wire rope slings and pendants\nsheathed in plastic. Consideration should be given to the use of wire rope slings and pendants without plastic sheathing, or an\nalternative method of encasing the sheath that allows for removal during inspection.\nThe vessel’s managers should ensure that wire rope slings and pendants are renewed regularly, following the same maintenance\nprinciples as lifeboat falls, as stipulated in SOLAS Chapter III, Regulation 20.4.\nWire-rope grips for the falls of life-saving appliances, such as bulldog grips, are not acceptable for any primary load-bearing\nterminations. This includes falls for lifeboats, rescue boats and davit-launched life rafts, as well as hanging off pendants and recovery\nstrops. Wire rope terminations are to be manufactured and the termination process is to be in accordance with the requirements of the\nmanufacturer and/or a National or International Standard. Wire rope grips are not to be used as the primary load bearing termination.\nA davit-launched rescue boat is typically deployed using standard electric or hydraulic power. In emergency situations, alternative\nmethods such as hydraulic accumulator power, compressed air, manual rotation, or gravity/crank mechanisms may be used.\nInspectors should confirm that officers and crew are familiar with the emergency operation of the davit, and verify that the rescue boat\ndavit is fully operational under both normal and emergency power sources.\nEach survival craft shall be stowed in a state of continuous readiness so that two crew members can carry out preparations for\nembarkation and launching in less than five minutes.\n(SOLAS 74,2020)\nFalls used in launching shall be inspected periodically with special regard for areas passing through sheaves and renewed when\nnecessary due to deterioration of the falls or at intervals of not more than five years – whichever is the earlier.\n(Measures to Prevent Accidents with Lifeboats, 2006)\nEach free-fall lifeboat shall be fitted with a release system which shall be designed to test the release system without launching the\nlifeboat.\nEach lifeboat shall be clearly marked with the number of persons for which the lifeboat is approved and the name and port of registry.\nMeans of identifying the ship to which the lifeboat belongs, and the number of the lifeboat shall be marked in such a way that they are\nvisible from above.\n(Life-saving appliances including LSA Code, 2017)\nThe release system of lifeboats, rescue boats, free-fall lifeboat including davit-launched life rafts shall be:\n> Maintained in accordance with instructions for on-board maintenance as required by regulation 36.\n> Subjected to a thorough examination and operational test during the annual surveys required by regulations I/7 and I/8 by\nproperly trained personnel familiar with the system; and\n> Operationally tested under a load of 1.1 times the total mass of the lifeboat when loaded with its full complement of person and\nequipment whenever the release gear is overhauled. Such over-hauling and testing shall be carried out at least once every five\nyears.\n(SOLAS 74,2020)\nDavit-launched life raft automatic release hooks shall be:\n> Maintained in accordance with instructions for on-board maintenance as required by regulation 36.\n> Subjected to a thorough examination and operational test during the annual surveys required by regulations I/7 and I/8 by\nproperly trained personnel familiar with the system; and\n> Operationally tested under a load of 1.1 times the total mass of the lifeboat when loaded with its full complement of person and\nequipment whenever the release gear is overhauled. Such over-hauling and test shall be carried out at least once every five years.\nNote: Of particular importance in the checking of lifeboats is the on-load release system fitted to enclosed lifeboats and the\nmaintenance routines for them. A high percentage of accidents at sea are attributed to lifeboats and their release systems.\n(Measure to Prevent Accident with Lifeboats, 2006)\nSOLAS Regulation III/1.5 requires all ships subject to SOLAS, regardless of build date, to identify existing on-load release\nmechanisms that do not comply with paragraphs 4.4.7.6.4 to 4.4.7.6.6 of the International Life-Saving Appliance (LSA) Code,\nas amended by IMO Resolution MSC.320 (89); and replace them with compliant release mechanisms no later than the next\nscheduled dry-docking after July 1, 2014 (but in any case, before July 1, 2019). SOLAS Regulation III/1.5 does not apply to the\nrelease mechanisms on free-fall lifeboats.\n(IMO Circular MSC.1/Circ.1392, Guidelines for Evaluation and Replacement of Lifeboat Release and Retrieval Systems)\nWire rope grips can be one of the most dangerous fitting if not used correctly. At least three wire rope grips should be used,\nwith the saddles on the live part of the rope, and the U-bolt pressing on the less heavily loaded tail of the rope. They should be\nspaced at least six wire diameters apart.\nThe operating instructions for the lifeboat and life raft shall be displayed.\nOn or near survival craft and their launching controls, posters or signs shall:\n1. Clearly indicate the purpose of the controls and the procedures for operating the appliance, as well as any pertinent\ninstructions or warnings.\n2. Be easily visible under emergency lighting conditions; and\n3. Use symbols consistent with resolution A.760, as amended by MSC.82.\n(SOLAS 74,2020)\nSome vessels may be equipped with a common davit to launch the rescue boat and the liferafts. These davits have two\nseparate hooks for lifting the rescue boat (on-load release) and the liferafts (off-load release). The hooks must be properly\nmarked and their use clearly understood by all personnel to avoid the wrong hook being used with the wrong type of\nequipment.\n(Survival Craft A Seafarer’s Guide 2008)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":56,"source_page_end":57,"raw_source_text":"Are the lifeboats, rescue boat and davit-launched life raft their equipment and launching\narrangements serviced periodically in good condition, and are the crew familiar with the\nlaunching procedure and operation? (V & M)\nGuide to Inspection\nWhen the vessel is equipped with a davit-launched life raft, the inspector shall check the crew’s familiarity with the operation of the\ndavit and test its operation.\nWire rope slings and pendants are occasionally sheathed in plastic by the manufacturer. This sheathing allows saltwater ingress,\nwhich aids corrosion by retaining moisture and prevents external inspection and the application of lubricant or other corrosion-\ninhibiting substances.\nThe vessel’s managers should establish a procedure for the regular inspection and maintenance of wire rope slings and pendants\nsheathed in plastic. Consideration should be given to the use of wire rope slings and pendants without plastic sheathing, or an\nalternative method of encasing the sheath that allows for removal during inspection.\nThe vessel’s managers should ensure that wire rope slings and pendants are renewed regularly, following the same maintenance\nprinciples as lifeboat falls, as stipulated in SOLAS Chapter III, Regulation 20.4.\nWire-rope grips for the falls of life-saving appliances, such as bulldog grips, are not acceptable for any primary load-bearing\nterminations. This includes falls for lifeboats, rescue boats and davit-launched life rafts, as well as hanging off pendants and recovery\nstrops. Wire rope terminations are to be manufactured and the termination process is to be in accordance with the requirements of the\nmanufacturer and/or a National or International Standard. Wire rope grips are not to be used as the primary load bearing termination.\nA davit-launched rescue boat is typically deployed using standard electric or hydraulic power. In emergency situations, alternative\nmethods such as hydraulic accumulator power, compressed air, manual rotation, or gravity/crank mechanisms may be used.\nInspectors should confirm that officers and crew are familiar with the emergency operation of the davit, and verify that the rescue boat\ndavit is fully operational under both normal and emergency power sources.\nEach survival craft shall be stowed in a state of continuous readiness so that two crew members can carry out preparations for\nembarkation and launching in less than five minutes.\n(SOLAS 74,2020)\nFalls used in launching shall be inspected periodically with special regard for areas passing through sheaves and renewed when\nnecessary due to deterioration of the falls or at intervals of not more than five years – whichever is the earlier.\n(Measures to Prevent Accidents with Lifeboats, 2006)\nEach free-fall lifeboat shall be fitted with a release system which shall be designed to test the release system without launching the\nlifeboat.\nEach lifeboat shall be clearly marked with the number of persons for which the lifeboat is approved and the name and port of registry.\nMeans of identifying the ship to which the lifeboat belongs, and the number of the lifeboat shall be marked in such a way that they are\nvisible from above.\n(Life-saving appliances including LSA Code, 2017)\nThe release system of lifeboats, rescue boats, free-fall lifeboat including davit-launched life rafts shall be:\n> Maintained in accordance with instructions for on-board maintenance as required by regulation 36.\n> Subjected to a thorough examination and operational test during the annual surveys required by regulations I/7 and I/8 by\nproperly trained personnel familiar with the system; and\n> Operationally tested under a load of 1.1 times the total mass of the lifeboat when loaded with its full complement of person and\nequipment whenever the release gear is overhauled. Such over-hauling and testing shall be carried out at least once every five\nyears.\n(SOLAS 74,2020)\nDavit-launched life raft automatic release hooks shall be:\n> Maintained in accordance with instructions for on-board maintenance as required by regulation 36.\n> Subjected to a thorough examination and operational test during the annual surveys required by regulations I/7 and I/8 by\nproperly trained personnel familiar with the system; and\n> Operationally tested under a load of 1.1 times the total mass of the lifeboat when loaded with its full complement of person and\nequipment whenever the release gear is overhauled. Such over-hauling and test shall be carried out at least once every five years.\nNote: Of particular importance in the checking of lifeboats is the on-load release system fitted to enclosed lifeboats and the\nmaintenance routines for them. A high percentage of accidents at sea are attributed to lifeboats and their release systems.\n(Measure to Prevent Accident with Lifeboats, 2006)\nSOLAS Regulation III/1.5 requires all ships subject to SOLAS, regardless of build date, to identify existing on-load release\nmechanisms that do not comply with paragraphs 4.4.7.6.4 to 4.4.7.6.6 of the International Life-Saving Appliance (LSA) Code,\nas amended by IMO Resolution MSC.320 (89); and replace them with compliant release mechanisms no later than the next\nscheduled dry-docking after July 1, 2014 (but in any case, before July 1, 2019). SOLAS Regulation III/1.5 does not apply to the\nrelease mechanisms on free-fall lifeboats.\n(IMO Circular MSC.1/Circ.1392, Guidelines for Evaluation and Replacement of Lifeboat Release and Retrieval Systems)\nWire rope grips can be one of the most dangerous fitting if not used correctly. At least three wire rope grips should be used,\nwith the saddles on the live part of the rope, and the U-bolt pressing on the less heavily loaded tail of the rope. They should be\nspaced at least six wire diameters apart.\nThe operating instructions for the lifeboat and life raft shall be displayed.\nOn or near survival craft and their launching controls, posters or signs shall:\n1. Clearly indicate the purpose of the controls and the procedures for operating the appliance, as well as any pertinent\ninstructions or warnings.\n2. Be easily visible under emergency lighting conditions; and\n3. Use symbols consistent with resolution A.760, as amended by MSC.82.\n(SOLAS 74,2020)\nSome vessels may be equipped with a common davit to launch the rescue boat and the liferafts. These davits have two\nseparate hooks for lifting the rescue boat (on-load release) and the liferafts (off-load release). The hooks must be properly\nmarked and their use clearly understood by all personnel to avoid the wrong hook being used with the wrong type of\nequipment.\n(Survival Craft A Seafarer’s Guide 2008)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.19","internal_question_no":"04A.019","question_sort_key":4101900.061,"question_text":"Are life rafts in good order and are hydrostatic release units maintained and installed correctly?","guide_to_inspection":"Cargo ships shall carry one or more inflatable or rigid liferafts, stowed in a position providing for easy side-to-side transfer at a single\nopen deck level and of such aggregate capacity as will accommodate the total number of persons on board. If not stowed in a position\nproviding for easy side-to-side transfer at a single open deck level, the total capacity available on each side shall be sufficient to\naccommodate the total number of persons on board.\nIf a free-fall lifeboat is fitted, cargo ships shall have one or more inflatable or rigid liferafts, on each side of the ship, of such aggregate\ncapacity as will accommodate the total number of persons on board. The liferafts on at least one side of the ship shall be served by\nlaunching appliances.\n(SOLAS 74,2020)\nFor davit launched liferafts, the launching appliance shall include an automatic release hook arranged so as to prevent premature\nrelease during lowering and shall release the liferaft when waterborne. The release hook shall include a capability to release the hook\nunder load. The on-load release control shall:\n> Be clearly differentiated from the control which activates the automatic release function;\n> Require at least two separate actions to operate;\n> Be designed such that crew members on deck can clearly observe when the release mechanism is properly and completely set.\n(Life-saving appliances including LSA Code, 2017)\nEvery liferaft shall be stowed with its painter permanently attached to the ship.\nEach liferaft or group of liferafts shall be stowed with a float-free arrangement so that each floats free and if inflatable, inflates\nautomatically when the ship sinks.\nLiferafts shall be so stowed as to permit manual release of one raft or container at a time from their securing arrangements.\n( SOLAS 74,2020)\nSome hydrostatic release manufacturers recommend that each liferaft is fitted with its own individual hydrostatic release unit (HRU), to\nprevent the possibility, where more than one liferaft is utilising the same release, of one of the liferafts breaking the weak link before the\nsecond or subsequent liferafts have inflated.\nWhen multiple liferafts are connected to a single HRU, each raft must be equipped with its own weak link. A HRU is not required for\nliferafts stored in the forward part of a vessel.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":57,"source_page_end":57,"raw_source_text":"Are life rafts in good order and are hydrostatic release units maintained and installed correctly? (V & M)\nGuide to Inspection\nCargo ships shall carry one or more inflatable or rigid liferafts, stowed in a position providing for easy side-to-side transfer at a single\nopen deck level and of such aggregate capacity as will accommodate the total number of persons on board. If not stowed in a position\nproviding for easy side-to-side transfer at a single open deck level, the total capacity available on each side shall be sufficient to\naccommodate the total number of persons on board.\nIf a free-fall lifeboat is fitted, cargo ships shall have one or more inflatable or rigid liferafts, on each side of the ship, of such aggregate\ncapacity as will accommodate the total number of persons on board. The liferafts on at least one side of the ship shall be served by\nlaunching appliances.\n(SOLAS 74,2020)\nFor davit launched liferafts, the launching appliance shall include an automatic release hook arranged so as to prevent premature\nrelease during lowering and shall release the liferaft when waterborne. The release hook shall include a capability to release the hook\nunder load. The on-load release control shall:\n> Be clearly differentiated from the control which activates the automatic release function;\n> Require at least two separate actions to operate;\n> Be designed such that crew members on deck can clearly observe when the release mechanism is properly and completely set.\n(Life-saving appliances including LSA Code, 2017)\nEvery liferaft shall be stowed with its painter permanently attached to the ship.\nEach liferaft or group of liferafts shall be stowed with a float-free arrangement so that each floats free and if inflatable, inflates\nautomatically when the ship sinks.\nLiferafts shall be so stowed as to permit manual release of one raft or container at a time from their securing arrangements.\n( SOLAS 74,2020)\nSome hydrostatic release manufacturers recommend that each liferaft is fitted with its own individual hydrostatic release unit (HRU), to\nprevent the possibility, where more than one liferaft is utilising the same release, of one of the liferafts breaking the weak link before the\nsecond or subsequent liferafts have inflated.\nWhen multiple liferafts are connected to a single HRU, each raft must be equipped with its own weak link. A HRU is not required for\nliferafts stored in the forward part of a vessel.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.20","internal_question_no":"04A.020","question_sort_key":4102000.062,"question_text":"Are life jackets in good condition, allocated as per the plan and donning instructions clearly displayed?","guide_to_inspection":"The vessel must carry: (a) a lifejacket for each person that the vessel is certified to carry, including a suitable lifejacket for\neach person aboard the vessel who weighs less than 32 kg; and (b) a sufficient number of lifejackets stowed in working\nspaces for the use of seafarers who may be required to remain on duty in those spaces. (2) A lifejacket for an adult must: (a)\nbe designed to fit a person weighing up to 140 kg and with a chest measurement of at least 1 750 mm; or (b) have available\nsuitable accessories to enable its use by that person.\nLifejackets selected for free-fall lifeboats and the manner in which they are carried or worn, shall not interfere with entry into\nthe lifeboat, occupant safety or operation of the lifeboat.\n(SOLAS 74, 2020)\nFor ships having keel laying on or after 01 July 2010, the method of securing the lifejacket to the wearer has quick and\npositive means of closure that do not require tying of knots.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":58,"source_page_end":58,"raw_source_text":"Are life jackets in good condition, allocated as per the plan and donning instructions clearly\ndisplayed? (V & M)\nGuide to Inspection\nThe vessel must carry: (a) a lifejacket for each person that the vessel is certified to carry, including a suitable lifejacket for\neach person aboard the vessel who weighs less than 32 kg; and (b) a sufficient number of lifejackets stowed in working\nspaces for the use of seafarers who may be required to remain on duty in those spaces. (2) A lifejacket for an adult must: (a)\nbe designed to fit a person weighing up to 140 kg and with a chest measurement of at least 1 750 mm; or (b) have available\nsuitable accessories to enable its use by that person.\nLifejackets selected for free-fall lifeboats and the manner in which they are carried or worn, shall not interfere with entry into\nthe lifeboat, occupant safety or operation of the lifeboat.\n(SOLAS 74, 2020)\nFor ships having keel laying on or after 01 July 2010, the method of securing the lifejacket to the wearer has quick and\npositive means of closure that do not require tying of knots.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.21","internal_question_no":"04A.021","question_sort_key":4102100.063,"question_text":"Are immersion suits in good condition, allocated as per the fire and safety plan and donning instructions clearly displayed?","guide_to_inspection":"The Guidelines for monthly shipboard inspection of immersion suits and anti-exposure suits (MSC/Circ.1047) are very\nhelpful in identifying obvious problems with a suit, but do not adequately address deterioration of seams and closures\n(zippers, etc.) which may not be readily apparent by visual inspection. Such deterioration can be detected by pressurisation of\nthe suit with air and testing the seams and closures for leaks with a soapy water solution.\nTo ensure the maintenance of adequate strength and watertightness of seams and closures of immersion suits and anti-\nexposure suits with age, it is recommended that each suit be subjected to an air pressure test such as the following, at\nintervals not exceeding three years, or more frequently for suits over ten years of age:\n> A suitable head piece, fitted with a means to inject air into the suit, should be inserted into the face orifice of the suit\nand secured so as to minimize leakage around the face seal. A low-pressure monitoring device, either integral to the\nfitting for air injection or as a separate device, should also be inserted. If the suit is fitted with detachable gloves and/or\nboots, the wrists and/or cuffs should be sealed by inserting a short length of suitable diameter plastic pipe and securing\nthe gloves and/or boots with suitable wire ties or hose clamps. The zipper should be fully zipped, and any face flap\nclosed. The suit should then be inflated to a pressure of 0.7 to 1.4 kPa (0.1 to 0.2 psi). If an auxiliary inflatable means\nof buoyancy is provided, it should be inflated through the oral valve to a pressure of 0.7 kPa (0.1 psi) or until firm to the\ntouch.\n> Each seam and closure of the suit and each seam, oral tube and attachment points and joint or valve of any auxiliary\ninflatable means of buoyancy should then be covered with a soapy water solution containing enough soap to produce\nbubbles (if leakage is noted at a foot valve to the extent that air pressure cannot be maintained, the valves should be\nsealed for the test).\n> If leaks are revealed by the propagation of bubbles at seams or closures, the leaking areas should be marked and,\nafter cleaning the suit thoroughly with fresh water and drying it, repaired in accordance with the suit manufacturer’s\nrecommendations.\n(MSC/Circ.1114 –Guidelines for Periodic Testing of Immersion Suit and Anti-Exposure Suit Seams and Closures, 2004)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":58,"source_page_end":58,"raw_source_text":"Are immersion suits in good condition, allocated as per the fire and safety plan and donning instructions\nclearly displayed? (V & M)\nGuide to Inspection\nThe Guidelines for monthly shipboard inspection of immersion suits and anti-exposure suits (MSC/Circ.1047) are very\nhelpful in identifying obvious problems with a suit, but do not adequately address deterioration of seams and closures\n(zippers, etc.) which may not be readily apparent by visual inspection. Such deterioration can be detected by pressurisation of\nthe suit with air and testing the seams and closures for leaks with a soapy water solution.\nTo ensure the maintenance of adequate strength and watertightness of seams and closures of immersion suits and anti-\nexposure suits with age, it is recommended that each suit be subjected to an air pressure test such as the following, at\nintervals not exceeding three years, or more frequently for suits over ten years of age:\n> A suitable head piece, fitted with a means to inject air into the suit, should be inserted into the face orifice of the suit\nand secured so as to minimize leakage around the face seal. A low-pressure monitoring device, either integral to the\nfitting for air injection or as a separate device, should also be inserted. If the suit is fitted with detachable gloves and/or\nboots, the wrists and/or cuffs should be sealed by inserting a short length of suitable diameter plastic pipe and securing\nthe gloves and/or boots with suitable wire ties or hose clamps. The zipper should be fully zipped, and any face flap\nclosed. The suit should then be inflated to a pressure of 0.7 to 1.4 kPa (0.1 to 0.2 psi). If an auxiliary inflatable means\nof buoyancy is provided, it should be inflated through the oral valve to a pressure of 0.7 kPa (0.1 psi) or until firm to the\ntouch.\n> Each seam and closure of the suit and each seam, oral tube and attachment points and joint or valve of any auxiliary\ninflatable means of buoyancy should then be covered with a soapy water solution containing enough soap to produce\nbubbles (if leakage is noted at a foot valve to the extent that air pressure cannot be maintained, the valves should be\nsealed for the test).\n> If leaks are revealed by the propagation of bubbles at seams or closures, the leaking areas should be marked and,\nafter cleaning the suit thoroughly with fresh water and drying it, repaired in accordance with the suit manufacturer’s\nrecommendations.\n(MSC/Circ.1114 –Guidelines for Periodic Testing of Immersion Suit and Anti-Exposure Suit Seams and Closures, 2004)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.22","internal_question_no":"04A.022","question_sort_key":4102200.064,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":58,"source_page_end":58,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.23","internal_question_no":"04A.023","question_sort_key":4102300.065,"question_text":"Has a sample of foam compound, applicable to both fixed and portable systems, been sent for regular testing and is evidence of satisfactory results available?","guide_to_inspection":"Protein-based alcohol-resistant foam concentrates should be subjected to a stability test with acetone. The first periodical\ncontrol of foam concentrates should be performed not more than three years after being supplied to the ship, and after that,\nevery year. The tests should be performed prior to delivery to the ship and annually thereafter\n(MSC.1/Circ.1312).\nPortable foam applicators:\n> Portable containers or portable tanks containing foam concentrate, excluding protein-based concentrates, less than\n10 years old, that remain factory sealed can normally be accepted without the periodical foam control tests required in\nMSC.1/Circ.1312 being carried out.\n> Protein based foam concentrate portable containers and portable tanks should be thoroughly checked and, if more\nthan five years old, the foam concentrate should be subjected to the periodical foam control tests required in MSC.1/\nCirc.1312, or renewed; and\n> The foam concentrates of any non-sealed portable containers and portable tanks, and portable containers and portable\ntanks where production data is not documented, should be subjected to the periodical foam control tests required in\nMSC.1/Circ.1312.\n(MSC.1/Circ.1432 -Revised guidelines for the maintenance and inspection of fire protection system and appliances 2012)\nPerfluoro-Octane Sulfonic Acid (hereinafter referred to as PFOS’) is known to be harmful to humans, other creatures and\nthe environment. Where fire-extinguishing media used or stored on ships are confirmed to contain PFOS, they need to be\ndisposed to appropriate shore-based reception facilities no later than the first survey on or after 1 January 2026.\n(Amendments to SOLAS regulations II-2/1.2.10 and II-2/10.11 as adopted by resolution MSC.532(107 2023)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":59,"source_page_end":59,"raw_source_text":"Has a sample of foam compound, applicable to both fixed and portable systems, been sent for regular\ntesting and is evidence of satisfactory results available? (M)\nGuide to Inspection\nProtein-based alcohol-resistant foam concentrates should be subjected to a stability test with acetone. The first periodical\ncontrol of foam concentrates should be performed not more than three years after being supplied to the ship, and after that,\nevery year. The tests should be performed prior to delivery to the ship and annually thereafter\n(MSC.1/Circ.1312).\nPortable foam applicators:\n> Portable containers or portable tanks containing foam concentrate, excluding protein-based concentrates, less than\n10 years old, that remain factory sealed can normally be accepted without the periodical foam control tests required in\nMSC.1/Circ.1312 being carried out.\n> Protein based foam concentrate portable containers and portable tanks should be thoroughly checked and, if more\nthan five years old, the foam concentrate should be subjected to the periodical foam control tests required in MSC.1/\nCirc.1312, or renewed; and\n> The foam concentrates of any non-sealed portable containers and portable tanks, and portable containers and portable\ntanks where production data is not documented, should be subjected to the periodical foam control tests required in\nMSC.1/Circ.1312.\n(MSC.1/Circ.1432 -Revised guidelines for the maintenance and inspection of fire protection system and appliances 2012)\nPerfluoro-Octane Sulfonic Acid (hereinafter referred to as PFOS’) is known to be harmful to humans, other creatures and\nthe environment. Where fire-extinguishing media used or stored on ships are confirmed to contain PFOS, they need to be\ndisposed to appropriate shore-based reception facilities no later than the first survey on or after 1 January 2026.\n(Amendments to SOLAS regulations II-2/1.2.10 and II-2/10.11 as adopted by resolution MSC.532(107 2023)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.24","internal_question_no":"04A.024","question_sort_key":4102400.066,"question_text":"Are fire mains and associated isolation valves, fire boxes, hoses, nozzles, applicators, and spanners regularly inspected and maintained and found to be in a satisfactory operating condition?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":59,"source_page_end":59,"raw_source_text":"Are fire mains and associated isolation valves, fire boxes, hoses, nozzles, applicators, and spanners\nregularly inspected and maintained and found to be in a satisfactory operating condition? (V & M)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.25","internal_question_no":"04A.025","question_sort_key":4102500.067,"question_text":"Are the International Shore Connection fitting arrangements clearly marked and well maintained and are the crew aware of their location?","guide_to_inspection":"There should be at least one shore connection for ship greater than 500GRT.\nThe international shore connection is a standard sized flange with nuts, bolts and washers and a coupling for ship’s fittings.\nThe fitting and joining must be suitable for a working pressure of 10.5 bar. Four bolts are required of 16mm diameter and\n50mm length, also eight washers and a gasket of any suitable material.\n(SOLAS 74, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":59,"source_page_end":59,"raw_source_text":"Are the International Shore Connection fitting arrangements clearly marked and well maintained and are\nthe crew aware of their location? (V)\nGuide to Inspection\nThere should be at least one shore connection for ship greater than 500GRT.\nThe international shore connection is a standard sized flange with nuts, bolts and washers and a coupling for ship’s fittings.\nThe fitting and joining must be suitable for a working pressure of 10.5 bar. Four bolts are required of 16mm diameter and\n50mm length, also eight washers and a gasket of any suitable material.\n(SOLAS 74, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.26","internal_question_no":"04A.026","question_sort_key":4102600.068,"question_text":"Are records available to show that fixed fire detection and fire alarm systems have been tested at regular intervals and maintained in good condition?","guide_to_inspection":"If a fire detection and alarm system is found to be malfunctioning, the machinery space shall not be operated in UMS mode\nuntil the system is repaired.\nPeriodically, fixed fire detectors and fire alarm systems shall be tested in accordance with MSC.1/Circ.1432 using equipment\nsuited to the types of fires to which the detector is designed to respond.\nIf indicated by the manufacturer, the test protocol and specialised test equipment should be followed and used.\nSpaces not covered by a fire detection system shall be covered by regular fire patrols.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":59,"source_page_end":59,"raw_source_text":"Are records available to show that fixed fire detection and fire alarm systems have been tested at regular\nintervals and maintained in good condition? (V)\nGuide to Inspection\nIf a fire detection and alarm system is found to be malfunctioning, the machinery space shall not be operated in UMS mode\nuntil the system is repaired.\nPeriodically, fixed fire detectors and fire alarm systems shall be tested in accordance with MSC.1/Circ.1432 using equipment\nsuited to the types of fires to which the detector is designed to respond.\nIf indicated by the manufacturer, the test protocol and specialised test equipment should be followed and used.\nSpaces not covered by a fire detection system shall be covered by regular fire patrols.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.27","internal_question_no":"04A.027","question_sort_key":4102700.069,"question_text":"Are the fixed fire extinguishing systems (where fitted) inspected, tested and in good order?","guide_to_inspection":"The inspector is not required to witness a physical test of the head of water mist systems unless there are visible potential defects\nwarranting such a test.\nFixed hold fire extinguishing systems, such as CO lines, should be blown through with compressed air and checked to ensure they\n2\nare free of dust and debris.\nPaint lockers shall be protected by:\n> A carbon dioxide system, designed to give a minimum volume of free gas equal to 40 % of the gross volume of the protected\nspace; or\n> A dry-powder system, designed for at least 0.5 kg powder/m³; or\n> A water-spraying or sprinkler system, designed for 5 l/m² min. Water spraying systems may be connected to the fire main of\nthe ship: or\n> A system providing equivalent protection, as determined by the Administration.\nIn any case, the system shall be operable from outside the protected space.\nFlammable liquid lockers shall be protected by an appropriate fire-extinguishing arrangement approved by the Administration.\nFor lockers of a deck area of less than 4 m², which do not give access to accommodation spaces, a carbon dioxide portable fire\nextinguisher sized to provide a minimum volume of free gas equal to 40 % of the gross volume of the space may be accepted in lieu\nof a fixed system. A discharge port shall be arranged in the locker to allow the discharge of the extinguisher without having to enter\ninto the protected space. The required portable fire extinguisher shall be stowed adjacent to the port. Alternatively, a port or hose\nconnection may be provided to facilitate the use of fire main water.\n(SOLAS 74, 2020)\nThe foam pump shall be maintained as per manufacturer recommendation and the inspector shall witness the free movement of\nthe foam pump when possible.\nFoam proportioners and other foam mixing devices should be tested to ensure they are operating within the correct mixing ratio\ntolerance atleast every five-yearly servicing.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":60,"source_page_end":60,"raw_source_text":"Are the fixed fire extinguishing systems (where fitted) inspected, tested and in good order? (V & M)\nGuide to Inspection\nThe inspector is not required to witness a physical test of the head of water mist systems unless there are visible potential defects\nwarranting such a test.\nFixed hold fire extinguishing systems, such as CO lines, should be blown through with compressed air and checked to ensure they\n2\nare free of dust and debris.\nPaint lockers shall be protected by:\n> A carbon dioxide system, designed to give a minimum volume of free gas equal to 40 % of the gross volume of the protected\nspace; or\n> A dry-powder system, designed for at least 0.5 kg powder/m³; or\n> A water-spraying or sprinkler system, designed for 5 l/m² min. Water spraying systems may be connected to the fire main of\nthe ship: or\n> A system providing equivalent protection, as determined by the Administration.\nIn any case, the system shall be operable from outside the protected space.\nFlammable liquid lockers shall be protected by an appropriate fire-extinguishing arrangement approved by the Administration.\nFor lockers of a deck area of less than 4 m², which do not give access to accommodation spaces, a carbon dioxide portable fire\nextinguisher sized to provide a minimum volume of free gas equal to 40 % of the gross volume of the space may be accepted in lieu\nof a fixed system. A discharge port shall be arranged in the locker to allow the discharge of the extinguisher without having to enter\ninto the protected space. The required portable fire extinguisher shall be stowed adjacent to the port. Alternatively, a port or hose\nconnection may be provided to facilitate the use of fire main water.\n(SOLAS 74, 2020)\nThe foam pump shall be maintained as per manufacturer recommendation and the inspector shall witness the free movement of\nthe foam pump when possible.\nFoam proportioners and other foam mixing devices should be tested to ensure they are operating within the correct mixing ratio\ntolerance atleast every five-yearly servicing.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.28","internal_question_no":"04A.028","question_sort_key":4102800.07,"question_text":"Is the emergency fire pump being regularly tested, in good operational condition and are starting instructions clearly posted?","guide_to_inspection":"When agreeable by the Chief Engineer and safe to do so, the inspector shall witness the starting and operation of the\nemergency fire pump and check the following:\n> Fire pumps should operate satisfactorily and be able to maintain proper pressure\n> Pressure gauges should be in good order\n> The operating condition of the priming system and/or non-return valve should be in good order\n> The operating condition of the isolating valves and cocks should be in good order\n> Witness delivered flow from hose with nozzle.\nAll fire pumps, including emergency fire pumps, must be flow tested once a year to ensure proper pressure and capacity\n(reference: MSC.1/Circ.1432).\nWhen possible and with the Master’s agreement, the inspector shall witness the test of the emergency fire pump’s capacity\nand pressure by deploying a fire hose on the bridge wing and another on the forecastle and observing the water flow.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":60,"source_page_end":60,"raw_source_text":"Is the emergency fire pump being regularly tested, in good operational condition and are starting\ninstructions clearly posted? (V)\nGuide to Inspection\nWhen agreeable by the Chief Engineer and safe to do so, the inspector shall witness the starting and operation of the\nemergency fire pump and check the following:\n> Fire pumps should operate satisfactorily and be able to maintain proper pressure\n> Pressure gauges should be in good order\n> The operating condition of the priming system and/or non-return valve should be in good order\n> The operating condition of the isolating valves and cocks should be in good order\n> Witness delivered flow from hose with nozzle.\nAll fire pumps, including emergency fire pumps, must be flow tested once a year to ensure proper pressure and capacity\n(reference: MSC.1/Circ.1432).\nWhen possible and with the Master’s agreement, the inspector shall witness the test of the emergency fire pump’s capacity\nand pressure by deploying a fire hose on the bridge wing and another on the forecastle and observing the water flow.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ31$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 3/15 imported.' AS result,
  '04A.008' AS chunk_first_question,
  '04A.028' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
